Good, I have all the context. Here are my suggestions for each item:

---

## Item 1: VBUS presence check is too permissive

**File:** `PowerApi.c:152`

The enum values are `SESSION_END=0x00`, `BELOW_AVALID=0x08`, `BELOW_VBUSVALID=0x10`, `VALID=0x18`. There's no `ABOVE_VBUSVALID` — `VALID` is the highest. So the fix is simply:

```c
// Current (too permissive — includes BELOW_VBUSVALID which isn't truly valid):
bool vbusPresent = (vbusLevel >= USBHS_VBUS_BELOW_VBUSVALID);

// Fix:
bool vbusPresent = (vbusLevel == USBHS_VBUS_VALID);
```

This ensures we only trigger the IINLIM state machine when VBUS is actually at a valid level, not when it's in a transitional state.

---

## Item 2: Config_Settings writes IINLIM during potential DPDM

**File:** `BQ24297.c:161-165`

`BQ24297_Config_Settings()` runs on first `Power_Tasks()` call. If VBUS is already present, DPDM is already running and will overwrite whatever we set. The `SetIINLIM(ILim_500)` is wasted. Just initialize the state machine and let it handle everything:

```c
// Current:
BQ24297_SetIINLIM(ILim_500);
pData->iinlimState = IINLIM_STATE_IDLE;
pData->iinlimLastVbus = false;

// Fix — just initialize state machine, skip the I2C write:
pData->iinlimState = IINLIM_STATE_IDLE;
pData->iinlimLastVbus = false;
pData->iinlimTimestamp = 0;
```

The state machine will detect the VBUS rising edge on the very next `Power_Tasks()` call and handle IINLIM properly. No point writing a value that DPDM will overwrite.

---

## Item 3: `pdMS_TO_TICKS` in SCPI_ForceDPDM

**File:** `SCPIInterface.c:1232`

```c
// Current (unsafe — could be 0 if portTICK_PERIOD_MS > 100):
vTaskDelay(100 / portTICK_PERIOD_MS);

// Fix:
vTaskDelay(pdMS_TO_TICKS(100));
```

Simple one-liner. `pdMS_TO_TICKS` is the correct portable macro.

---

## Item 4: SCPI_GetBQDiagnostics missing 0xFF checks

**File:** `SCPIInterface.c:1294-1335`

`SCPI_GetBQRegisters` properly checks each register for `0xFF`, but `SCPI_GetBQDiagnostics` doesn't. Add per-register error guards consistent with the pattern already used in `SCPI_GetBQRegisters`:

```c
    // Read raw registers for fields not in status struct
    uint8_t reg00 = BQ24297_Read_I2C(0x00);
    uint8_t reg01 = BQ24297_Read_I2C(0x01);
    uint8_t reg07 = BQ24297_Read_I2C(0x07);
    uint8_t reg08 = BQ24297_Read_I2C(0x08);
    uint8_t reg09 = BQ24297_Read_I2C(0x09);

    const char* iinlimStr[] = {"100mA","150mA","500mA","900mA","1A","1.5A","2A","3A"};

    if (reg00 == 0xFF) {
        scpi_printf(context, "  REG00=ERR (I2C read failed)\r\n");
    } else {
        uint8_t vindpm = (reg00 >> 3) & 0x0F;
        uint8_t iinlim = reg00 & 0x07;
        scpi_printf(context,
            "  REG00=0x%02X (Input):  HIZ=%d | VINDPM=%dmV (%d) | IINLIM=%s (%d)\r\n",
            reg00, (reg00 >> 7) & 1, 3880 + vindpm * 80, vindpm,
            iinlimStr[iinlim], iinlim);
    }

    if (reg01 == 0xFF) {
        scpi_printf(context, "  REG01=ERR (I2C read failed)\r\n");
    } else {
        uint8_t sysMin = (reg01 >> 1) & 0x07;
        scpi_printf(context,
            "  REG01=0x%02X (Config): OTG=%d | CHG=%d | SYS_MIN=%dmV (%d)\r\n",
            reg01, (reg01 >> 5) & 1, (reg01 >> 4) & 1, 3000 + sysMin * 100, sysMin);
    }

    if (reg07 == 0xFF) {
        scpi_printf(context, "  REG07=ERR (I2C read failed)\r\n");
    } else {
        scpi_printf(context,
            "  REG07=0x%02X (Misc):   DPDM=%d | BATFET=%s (%d)\r\n",
            reg07, (reg07 >> 7) & 1,
            (reg07 & 0x20) ? "Disabled" : "Enabled", (reg07 >> 5) & 1);
    }

    const char* vbusStr[] = {"Unknown","USB_SDP","Adapter","OTG"};
    const char* chgStr[] = {"Not charging","Pre-charge","Fast charge","Charge done"};

    if (reg08 == 0xFF) {
        scpi_printf(context, "  REG08=ERR (I2C read failed)\r\n");
    } else {
        uint8_t vbusStat = (reg08 >> 6) & 0x03;
        uint8_t chgStat = (reg08 >> 4) & 0x03;
        scpi_printf(context,
            "  REG08=0x%02X (Status): VBUS=%s (%d) | Charge=%s (%d) | PG=%d | DPM=%d | THERM=%d | VSYS=%d\r\n",
            reg08, vbusStr[vbusStat], vbusStat, chgStr[chgStat], chgStat,
            (reg08 >> 2) & 1, (reg08 >> 3) & 1, (reg08 >> 1) & 1, reg08 & 1);
    }

    const char* chgFaultStr[] = {"Normal","Input fault","Thermal","Timer"};
    const char* ntcFaultStr[] = {"Ok","Hot","Cold","Hot/Cold"};

    if (reg09 == 0xFF) {
        scpi_printf(context, "  REG09=ERR (I2C read failed)\r\n");
    } else {
        uint8_t chgFault = (reg09 >> 4) & 0x03;
        uint8_t ntcFault = reg09 & 0x07;
        scpi_printf(context,
            "  REG09=0x%02X (Faults): Watchdog=%d | OTG=%d | CHG=%s (%d) | BAT=%d | NTC=%s (%d)\r\n",
            reg09, (reg09 >> 7) & 1, (reg09 >> 6) & 1,
            chgFaultStr[chgFault], chgFault, (reg09 >> 3) & 1,
            (ntcFault < 4) ? ntcFaultStr[ntcFault] : "Fault", ntcFault);
    }
```

---

## Item 5: Timeout path in WAIT_DPDM doesn't check SetIINLIM return

**File:** `BQ24297.c:495-501`

The success path (line 487) checks the return value but the timeout path (line 499) doesn't:

```c
// Current:
} else if (timeout) {
    LOG_E("IINLIM: DPDM not complete after 3s (REG07=0x%02X), forcing 500mA", reg07);
    BQ24297_SetIINLIM(ILim_500);
    pData->iinlimTimestamp = now;
    pData->iinlimState = IINLIM_STATE_WAIT_USB;
}

// Fix — check return, retry on failure:
} else if (timeout) {
    LOG_E("IINLIM: DPDM not complete after 3s (REG07=0x%02X), forcing 500mA", reg07);
    if (BQ24297_SetIINLIM(ILim_500)) {
        pData->iinlimTimestamp = now;
        pData->iinlimState = IINLIM_STATE_WAIT_USB;
    } else {
        LOG_E("IINLIM: Failed to set 500mA on timeout, retrying next cycle");
    }
}
```

---

## Item 6: scpi_printf buffer size

**File:** `SCPIInterface.h:29`

Some diagnostic lines (especially the REG08 status line) are close to 128 bytes. Bump to 192 to give comfortable headroom without being wasteful on stack:

```c
// Current:
char buf[128];

// Fix:
char buf[192];
```

Also update the doc comment on line 24 from "128-byte buffer" to "192-byte buffer".

---

**Summary table:**

| # | File | Risk | Effort |
|---|------|------|--------|
| 1 | `PowerApi.c:152` | Medium — false VBUS triggering | 1 line |
| 2 | `BQ24297.c:161-165` | Low — wasted I2C write, potential DPDM conflict | 3 lines |
