217→    USB_DEVICE_EVENT_DATA_CONFIGURED *configuredEventData;
218→
219→    switch (event) {
220→        case USB_DEVICE_EVENT_DECONFIGURED:
221→        case USB_DEVICE_EVENT_RESET:
222→            gRunTimeUsbSttings.isConfigured = false;
223→            if (gRunTimeUsbSttings.deviceHandle != USB_DEVICE_HANDLE_INVALID) {
224→                gRunTimeUsbSttings.state = USB_CDC_STATE_BEGIN_CLOSE;
225→            }
226→            break;
227→        case USB_DEVICE_EVENT_CONFIGURED:
228→
229→            /* Check the configuration. We only support configuration 1 */
230→            configuredEventData = (USB_DEVICE_EVENT_DATA_CONFIGURED*) eventData;
231→            if (configuredEventData->configurationValue == 1) {
232→                /* Register the CDC Device application event handler here.
233→                 * Note how the usbCdcData object pointer is passed as the
234→                 * user data */
235→                USB_DEVICE_CDC_EventHandlerSet(
236→                        USB_DEVICE_CDC_INDEX_0,
237→                        UsbCdc_CDCEventHandler,
238→                        (uintptr_t) & gRunTimeUsbSttings);
239→
240→                /* Mark that the device is now configured */
241→                gRunTimeUsbSttings.state = USB_CDC_STATE_WAIT;
242→                gRunTimeUsbSttings.isConfigured = true;
243→            }
244→            break;
245→
246→        case USB_DEVICE_EVENT_POWER_DETECTED:
247→
248→            /* VBUS was detected. This callback runs in the USB device task context,
249→             * so vTaskDelay yields CPU to other tasks (does not block the system).
250→             *
251→             * 100ms delay: lets the RC low-pass filter on the VBUS sense line
252→             * settle before we attach. Previously 1000ms to wait for BQ24297
253→             * DPDM detection; reduced now that ManageIINLIM handles IINLIM
254→             * independently via I2C.
255→             *
256→             * Re-check isVbusDetected after the delay in case POWER_REMOVED
257→             * fired while we were waiting (cable yanked during settle). */
258→            gRunTimeUsbSttings.isVbusDetected = true;
259→            gRunTimeUsbSttings.isConfigured = false;
260→
261→            vTaskDelay(pdMS_TO_TICKS(100));
262→            if (gRunTimeUsbSttings.isVbusDetected &&
263→                gRunTimeUsbSttings.deviceHandle != USB_DEVICE_HANDLE_INVALID) {
264→                USB_DEVICE_Attach(gRunTimeUsbSttings.deviceHandle);
265→            }
266→            break;
267→
268→        case USB_DEVICE_EVENT_POWER_REMOVED:
269→        {
270→            /* VBUS Sag vs Real Removal Detection:
271→             *
272→             * Power sag: Internal power rail transitions can cause VBUS to
273→             * momentarily sag from ~5V to ~4V, triggering a false removal event.
274→             * VBUS recovers within ~20ms for sag events.
275→             *
276→             * Real removal: The low-pass RC filter on VBUS into the PIC32 causes
277→             * the voltage to discharge over 20-50ms when power is unplugged.
278→             *
279→             * Solution: If VBUS is still elevated, wait 50ms for the RC filter
280→             * to discharge and re-check. If VBUS recovered, it was a sag. If
281→             * VBUS dropped, it was a real removal. */
282→            USBHS_VBUS_LEVEL vbusLevel = PLIB_USBHS_VBUSLevelGet(USBHS_ID_0);
283→
284→            if (vbusLevel >= USBHS_VBUS_BELOW_VBUSVALID) {
285→                /* VBUS still elevated - wait for RC filter discharge */
286→                vTaskDelay(50 / portTICK_PERIOD_MS);
287→                vbusLevel = PLIB_USBHS_VBUSLevelGet(USBHS_ID_0);
288→
289→                if (vbusLevel >= USBHS_VBUS_BELOW_VBUSVALID) {
290→                    /* VBUS recovered - power sag, not real removal */
291→                    break;
292→                }
293→            }
294→
295→            /* VBUS truly removed */
296→            gRunTimeUsbSttings.isVbusDetected = false;
297→            gRunTimeUsbSttings.isConfigured = false;
298→            if (gRunTimeUsbSttings.deviceHandle != USB_DEVICE_HANDLE_INVALID) {
299→                USB_DEVICE_Detach(gRunTimeUsbSttings.deviceHandle);
300→            }
301→            break;
302→        }
303→
304→        case USB_DEVICE_EVENT_SUSPENDED:
305→            // Transfer handles become invalid during suspend - host stops all transfers
306→            // Current implementation transitions to WAIT state which will re-establish transfers
307→            UsbCdc_SleepStateUpdateCB(true);
308→            gRunTimeUsbSttings.state = USB_CDC_STATE_WAIT;
309→            break;
310→        case USB_DEVICE_EVENT_RESUMED:
311→            // Suspend/resume only occurs after device is configured and enumerated
312→            UsbCdc_SleepStateUpdateCB(false);
313→            gRunTimeUsbSttings.state = USB_CDC_STATE_WAIT;
