315→        case USB_DEVICE_EVENT_ERROR:
316→            // Some errors may be non-fatal (transient bus errors, CRC errors)
317→            // but conservative approach is to reset the interface
318→            gRunTimeUsbSttings.state = USB_CDC_STATE_BEGIN_CLOSE;
