339→    }
340→
341→    // Begin atomic section to prevent race conditions with concurrent writes
342→    taskENTER_CRITICAL();
343→
344→    // Check if previous write is still pending to prevent buffer corruption
345→    if (gRunTimeUsbSttings.writeTransferHandle != USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID) {
346→        taskEXIT_CRITICAL();
347→        return -1;  // Previous write still in progress
348→    }
349→
350→    // Prepare buffer while in atomic section to prevent another task from corrupting it
351→    memcpy(gRunTimeUsbSttings.writeBuffer, buf, (size_t)len);
352→    gRunTimeUsbSttings.writeBufferLength = len;
353→    gRunTimeUsbSttings.writeTransferHandle = USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID;
354→
355→    taskEXIT_CRITICAL();
356→
357→    // Call USB driver outside critical section (may block/take time)
358→    USB_DEVICE_CDC_RESULT writeResult = USB_DEVICE_CDC_Write(USB_DEVICE_CDC_INDEX_0,
359→            &gRunTimeUsbSttings.writeTransferHandle,
360→            gRunTimeUsbSttings.writeBuffer,
361→            len,
362→            USB_DEVICE_CDC_TRANSFER_FLAGS_DATA_COMPLETE);
363→
364→    if (writeResult != USB_DEVICE_CDC_RESULT_OK) {
365→        // Write failed - ensure handle is invalid (atomic update)
366→        taskENTER_CRITICAL();
367→        gRunTimeUsbSttings.writeTransferHandle = USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID;
368→        gRunTimeUsbSttings.writeBufferLength = 0;
369→        taskEXIT_CRITICAL();
370→        return -1;
371→    }
372→
373→    // Success: report bytes accepted for transfer
374→    // Note: Don't check if handle is still valid here - the write complete interrupt
375→    // can fire so fast that UsbCdc_FinalizeWrite already reset it to INVALID
376→    return (int)len;
377→}
