379→/**
380→ * Enqueues client data for writing 
381→ */
382→static bool UsbCdc_BeginWrite(UsbCdcData_t* client) {
383→
384→    USB_DEVICE_CDC_RESULT writeResult = USB_DEVICE_CDC_RESULT_OK;
385→
386→    if (client->state != USB_CDC_STATE_PROCESS) {
387→        return false;
388→    }
389→
390→    // make sure there is no write transfer in progress
391→    if (client->writeTransferHandle == USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID) {
392→        xSemaphoreTake(client->wMutex, portMAX_DELAY);
393→        if (CircularBuf_NumBytesAvailable(&client->wCirbuf) > 0) {
394→            CircularBuf_ProcessBytes(&client->wCirbuf, NULL, USBCDC_WBUFFER_SIZE, &writeResult);
395→        } else {
396→            // No data to write, return true (success - nothing to do)
397→            xSemaphoreGive(client->wMutex);
398→            return true;
399→        }
400→        xSemaphoreGive(client->wMutex);
401→
402→        // CircularBuffer callback now returns bytes written (>= 0) on success, < 0 on error
403→        // Handle errors
404→        if (writeResult < 0) {
405→            switch (writeResult) {
406→                case USB_DEVICE_CDC_RESULT_ERROR_INSTANCE_NOT_CONFIGURED:
407→                case USB_DEVICE_CDC_RESULT_ERROR_INSTANCE_INVALID:
408→                case USB_DEVICE_CDC_RESULT_ERROR_PARAMETER_INVALID:
409→                case USB_DEVICE_CDC_RESULT_ERROR_ENDPOINT_HALTED:
410→                case USB_DEVICE_CDC_RESULT_ERROR_TERMINATED_BY_HOST:
411→                    // Reset the interface
412→                    gRunTimeUsbSttings.state = USB_CDC_STATE_BEGIN_CLOSE;
413→                    return false;
414→
415→                case USB_DEVICE_CDC_RESULT_ERROR_TRANSFER_SIZE_INVALID: // Bad input (GIGO)
416→                    SYS_DEBUG_MESSAGE(SYS_ERROR_ERROR, "Bad USB write size");
417→                    return false;
418→                case USB_DEVICE_CDC_RESULT_ERROR_TRANSFER_QUEUE_FULL: // Too many pending requests. Just wait.
419→                case USB_DEVICE_CDC_RESULT_ERROR: // Concurrency issue. Just wait.
420→                default:
421→                    // No action
422→                    return false;
423→            }
424→        }
425→
426→        // Success: callback returned bytes written (>= 0)
427→        return true;
428→    }
429→
430→    return false;
431→}
