461→/**
462→ * Starts listening for a read
463→ */
464→static bool UsbCdc_BeginRead(UsbCdcData_t* client) {
465→    if (client->state != USB_CDC_STATE_PROCESS) {
466→        return false;
467→    }
468→    // Schedule the next read
469→    if (gRunTimeUsbSttings.readTransferHandle ==
470→            USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID &&
471→            gRunTimeUsbSttings.readBufferLength == 0) {
472→        USB_DEVICE_CDC_RESULT readResult = USB_DEVICE_CDC_Read(
473→                USB_DEVICE_CDC_INDEX_0,
474→                &gRunTimeUsbSttings.readTransferHandle,
475→                client->readBuffer, USBCDC_RBUFFER_SIZE);
476→
477→        switch (readResult) {
478→            case USB_DEVICE_CDC_RESULT_OK:
479→                // Normal operation
480→                break;
481→
482→            case USB_DEVICE_CDC_RESULT_ERROR_INSTANCE_NOT_CONFIGURED:
483→            case USB_DEVICE_CDC_RESULT_ERROR_INSTANCE_INVALID:
484→            case USB_DEVICE_CDC_RESULT_ERROR_PARAMETER_INVALID:
485→            case USB_DEVICE_CDC_RESULT_ERROR_ENDPOINT_HALTED:
486→            case USB_DEVICE_CDC_RESULT_ERROR_TERMINATED_BY_HOST:
487→                // Reset the interface
488→                gRunTimeUsbSttings.state = USB_CDC_STATE_BEGIN_CLOSE;
489→                return false;
490→
491→            case USB_DEVICE_CDC_RESULT_ERROR_TRANSFER_SIZE_INVALID: // Bad input (GIGO)
492→                SYS_DEBUG_MESSAGE(SYS_ERROR_ERROR, "Bad USB read size");
493→                return false;
494→            case USB_DEVICE_CDC_RESULT_ERROR_TRANSFER_QUEUE_FULL: // Too many pending requests. Just wait.
495→            case USB_DEVICE_CDC_RESULT_ERROR: // Concurrency issue. Just wait. 
496→            default:
497→                // No action
498→                return false;
499→        }
500→
501→        if (gRunTimeUsbSttings.readTransferHandle ==
502→                USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID) {
503→            SYS_DEBUG_MESSAGE(SYS_ERROR_ERROR, "Non-error w/ invalid transfer handle");
504→            return false;
505→        }
506→    }
507→
508→    return true;
509→
510→}
