531→/**
532→ * Called to complete a read operation, feeding data to the rest of the system
533→ */
534→static bool UsbCdc_FinalizeRead(UsbCdcData_t* client) {
535→    static const char UNSET_TRANSPARENT_MODE_COMMAND[] = "SYSTem:USB:SetTransparentMode 0"; // NOTE: PuTTY sends \r not \r\n by default so we are going to check for all terminating scenarios below
536→    static uint8_t transparentModeCmdLength = 0;
537→    
538→    if (client->readBufferLength > 0) {
539→        if (client->isTransparentModeActive == 0) {
540→            for (size_t i = 0; i < client->readBufferLength; ++i) {
541→                // Filter out potentially dangerous characters
542→                if (UsbCdc_IsCharacterSafe(client, client->readBuffer[i])) {
543→                    microrl_insert_char(&client->console, client->readBuffer[i]);
544→                } else {
545→                    // Silently reject unsafe characters to avoid information disclosure
546→                    // Character filtering is documented in the system design
547→                }
548→            }
549→            client->readBufferLength = 0;
550→            return true;
551→        } else { 
552→            // IMPORTANT: Transparent mode should NOT filter characters
553→            // This mode is used for raw binary data passthrough (e.g., firmware updates)
554→            // Filtering would corrupt the data stream
555→            
556→            // Check for UNSET_TRANSPARENT_MODE_COMMAND length plus up to two terminating characters (\n\r).
557→            transparentModeCmdLength = strlen(UNSET_TRANSPARENT_MODE_COMMAND);
558→            if ((client->readBufferLength == transparentModeCmdLength) ||       \
559→                (client->readBufferLength == transparentModeCmdLength + 1) ||   \
560→                (client->readBufferLength == transparentModeCmdLength + 2)) {
561→                //  Now check to see if the string actually matches the command UNSET_TRANSPARENT_MODE_COMMAND
562→                if ((strspn(UNSET_TRANSPARENT_MODE_COMMAND, (const char *)client->readBuffer)) == transparentModeCmdLength) {
563→                    for (size_t i = 0; i < transparentModeCmdLength; ++i) {
564→                        microrl_insert_char(&client->console, client->readBuffer[i]);
565→                    }
566→                    // Since we truncated the read buffer, be sure to pass the proper termination characters
567→                    microrl_insert_char(&client->console, '\n');
568→                    microrl_insert_char(&client->console, '\r');
569→                }
570→                client->readBufferLength = 0;
571→                return true;
572→            }
573→            if (UsbCdc_TransparentReadCmpltCB(client->readBuffer, client->readBufferLength) == true) {
574→                client->readBufferLength = 0;
575→                return true;
576→            }
577→        }
578→    }
579→    return false;
580→
581→}
