583→size_t UsbCdc_WriteBuffFreeSize(UsbCdcData_t* client) {
584→    if (client == NULL) {
585→        client = &gRunTimeUsbSttings;
586→    }
587→    if (gRunTimeUsbSttings.state != USB_CDC_STATE_PROCESS)
588→        return 0;
589→    
590→    // Must protect circular buffer access with mutex
591→    xSemaphoreTake(client->wMutex, portMAX_DELAY);
592→    size_t freeSize = CircularBuf_NumBytesFree(&client->wCirbuf);
593→    xSemaphoreGive(client->wMutex);
594→    
595→    return freeSize;
596→}
597→
598→size_t UsbCdc_WriteToBuffer(UsbCdcData_t* client, const char* data, size_t len) {
599→    if (client == NULL) {
600→        client = &gRunTimeUsbSttings;
601→    }
602→
603→    if (len == 0) return 0;
604→
605→    // Non-blocking check for buffer space
606→    // Use try-lock (timeout=0) to keep function truly non-blocking
607→    // If mutex is busy or buffer is full, return 0 immediately
608→    if (xSemaphoreTake(client->wMutex, 0) != pdTRUE) {
609→        return 0;  // Mutex busy, can't write now
610→    }
611→
612→    size_t currentFree = CircularBuf_NumBytesFree(&client->wCirbuf);
613→    if (currentFree == 0) {
614→        xSemaphoreGive(client->wMutex);
615→        return 0;
616→    }
617→
618→    // Partial write - clamp to chunk size for better flow control
619→    // Limit to USBCDC_WBUFFER_SIZE to align with USB driver transfer granularity
620→    size_t toWrite = len;
621→    if (toWrite > currentFree) {
622→        toWrite = currentFree;
623→    }
624→    if (toWrite > USBCDC_WBUFFER_SIZE) {
625→        toWrite = USBCDC_WBUFFER_SIZE;
626→    }
627→
628→    size_t bytesAdded = CircularBuf_AddBytes(&client->wCirbuf, (uint8_t*) data, toWrite);
629→    xSemaphoreGive(client->wMutex);
630→
631→    return bytesAdded;
632→}
