685→static int SCPI_USB_Error(scpi_t * context, int_fast16_t err) {
686→    char ip[100];
687→    // Don't print "No error" messages - err code 0 is used internally by SCPI lib
688→    if (err != 0) {
689→        sprintf(ip, "**ERROR: %d, \"%s\"\r\n", (int32_t) err, SCPI_ErrorTranslate(err));
690→        size_t len = strlen(ip);
691→        size_t written = context->interface->write(context, ip, len);
692→        if (written != len) {
693→            // Write error occurred, but we can't do much about it in error handler
694→            // The error has been formatted, partial write is better than none
695→        }
696→    }
697→    return 0;
698→}
