737→/**
738→ * Called to process a completed command
739→ * @param context The console theat made this call
740→ * @param commandLen The length of the command
741→ * @param command The command to process
742→ * @return The result of processing the command, or -1 if the command is invalid;
743→ */
744→static int microrl_commandComplete(microrl_t* context, size_t commandLen, const char* command) {
745→    UNUSED(context);
746→
747→    if (command != NULL && commandLen > 0) {
748→        // Store command in history buffer
749→        size_t copyLen = (commandLen < SCPI_CMD_MAX_LENGTH - 1) ? commandLen : SCPI_CMD_MAX_LENGTH - 1;
750→        memcpy(gRunTimeUsbSttings.cmdHistory[gRunTimeUsbSttings.cmdHistoryHead], command, copyLen);
751→        gRunTimeUsbSttings.cmdHistory[gRunTimeUsbSttings.cmdHistoryHead][copyLen] = '\0';
752→        
753→        // Update circular buffer indices
754→        gRunTimeUsbSttings.cmdHistoryHead = (gRunTimeUsbSttings.cmdHistoryHead + 1) % SCPI_CMD_HISTORY_SIZE;
755→        if (gRunTimeUsbSttings.cmdHistoryCount < SCPI_CMD_HISTORY_SIZE) {
756→            gRunTimeUsbSttings.cmdHistoryCount++;
757→        }
758→        
759→        // Log the SCPI command received
760→        LOG_D("SCPI CMD: %.*s\r\n", commandLen, command);
761→        
762→        int result = SCPI_Input(
763→                &gRunTimeUsbSttings.scpiContext,
764→                command,
765→                commandLen);
766→        
767→        // Check for SCPI errors including buffer overrun
768→        if (SCPI_ErrorCount(&gRunTimeUsbSttings.scpiContext) > 0) {
769→            scpi_error_t error;
770→            while (SCPI_ErrorPop(&gRunTimeUsbSttings.scpiContext, &error)) {
771→                const char* error_str = SCPI_ErrorTranslate(error.error_code);
772→                LOG_E("SCPI Error %d: %s\r\n", error.error_code, error_str ? error_str : "Unknown");
773→            }
774→        }
775→        
776→        // Ensure any SCPI responses are flushed to the USB immediately
777→        // This prevents the desktop app from hanging when waiting for responses
778→        if (result > 0) {
779→            UsbCdc_BeginWrite(&gRunTimeUsbSttings);
780→        }
781→        
782→        return result;
783→    }
784→
785→    SYS_DEBUG_MESSAGE(SYS_ERROR_ERROR, "NULL or zero length command.");
786→    return -1;
787→}
