793→void UsbCdc_Initialize() {
794→
795→    gRunTimeUsbSttings.state = USB_CDC_STATE_INIT;
796→
797→    gRunTimeUsbSttings.deviceHandle = USB_DEVICE_HANDLE_INVALID;
798→    gRunTimeUsbSttings.isVbusDetected = false;
799→    gRunTimeUsbSttings.isConfigured = false;
800→
801→    gRunTimeUsbSttings.deviceLineCodingData.dwDTERate = 9600;
802→    gRunTimeUsbSttings.deviceLineCodingData.bParityType = 0;
803→    gRunTimeUsbSttings.deviceLineCodingData.bParityType = 0;
804→    gRunTimeUsbSttings.deviceLineCodingData.bDataBits = 8;
805→
806→    gRunTimeUsbSttings.readTransferHandle =
807→            USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID;
808→    gRunTimeUsbSttings.writeTransferHandle =
809→            USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID;
810→    gRunTimeUsbSttings.readBufferLength = 0;
811→
812→    microrl_init(&gRunTimeUsbSttings.console, microrl_echo);
813→    microrl_set_echo(&gRunTimeUsbSttings.console, true);
814→    microrl_set_execute_callback(
815→            &gRunTimeUsbSttings.console,
816→            microrl_commandComplete);
817→    gRunTimeUsbSttings.scpiContext = CreateSCPIContext(&scpi_interface, &gRunTimeUsbSttings);
818→
819→    // reset circular buffer variables to known state. 
820→    CircularBuf_Init(&gRunTimeUsbSttings.wCirbuf,
821→            UsbCdc_Wrapper_Write,
822→            (USBCDC_CIRCULAR_BUFF_SIZE));
823→    /* Create a mutex type semaphore. */
824→    gRunTimeUsbSttings.wMutex = xSemaphoreCreateMutex();
825→
826→    if (gRunTimeUsbSttings.wMutex == NULL) {
827→        /* The semaphore was created successfully and
828→        can be used. */
829→    }
830→
831→    //Release ownership of the mutex object
832→    xSemaphoreGive(gRunTimeUsbSttings.wMutex);
833→    
834→    // Initialize escape sequence state
835→    gRunTimeUsbSttings.escapeState = ESC_STATE_NONE;
836→
837→}
