839→void UsbCdc_ProcessState() {
840→
841→    UNUSED(UsbCdc_WaitForRead); // We dont want to block on the read so this is currently not used
842→
843→    switch (gRunTimeUsbSttings.state) {
844→        case USB_CDC_STATE_INIT:
845→            //GPIO_WritePin(g_boardState.led2Id, false);
846→
847→            /* Open the device layer */
848→            gRunTimeUsbSttings.deviceHandle = USB_DEVICE_Open(USB_DEVICE_INDEX_0, DRV_IO_INTENT_READWRITE);
849→
850→            if (gRunTimeUsbSttings.deviceHandle != USB_DEVICE_HANDLE_INVALID) {
851→                /* Register a callback with device layer to get event notification (for end point 0) */
852→                USB_DEVICE_EventHandlerSet(
853→                        gRunTimeUsbSttings.deviceHandle,
854→                        UsbCdc_EventHandler,
855→                        0);
856→
857→                gRunTimeUsbSttings.state = USB_CDC_STATE_WAIT;
858→            } else {
859→                /* The Device Layer is not ready to be opened. We should try
860→                 * again later. */
861→            }
862→
863→            break;
864→        case USB_CDC_STATE_PROCESS:
865→            // If a write operation is not in progress
866→            if (gRunTimeUsbSttings.readTransferHandle ==
867→                    USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID) {
868→                // Process any input
869→                UsbCdc_FinalizeRead(&gRunTimeUsbSttings);
870→
871→                // Schedule the next read
872→                if (!UsbCdc_BeginRead(&gRunTimeUsbSttings)) {
873→                    break;
874→                }
875→            }
876→
877→            // I a read operation is not in progress
878→            if (gRunTimeUsbSttings.writeTransferHandle ==
879→                    USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID) {
880→                // Schedule any output;
881→                if (!UsbCdc_BeginWrite(&gRunTimeUsbSttings)) {
882→                    break;
883→                }
884→
885→            }
886→
887→            break;
888→        case USB_CDC_STATE_BEGIN_CLOSE:
889→            //GPIO_WritePin(g_boardState.led2Id, false);
890→
891→            if (gRunTimeUsbSttings.deviceHandle != USB_DEVICE_HANDLE_INVALID) {
892→                USB_DEVICE_Close(gRunTimeUsbSttings.deviceHandle);
893→                gRunTimeUsbSttings.deviceHandle = USB_DEVICE_HANDLE_INVALID;
894→
895→                gRunTimeUsbSttings.state = USB_CDC_STATE_WAIT;
896→            }
897→
898→            gRunTimeUsbSttings.state = USB_CDC_STATE_CLOSED;
899→
900→            break;
901→        case USB_CDC_STATE_CLOSED:
902→            //GPIO_WritePin(g_boardState.led2Id, false);
903→
904→            gRunTimeUsbSttings.deviceHandle = USB_DEVICE_HANDLE_INVALID;
905→
906→            gRunTimeUsbSttings.readTransferHandle =
907→                    USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID;
908→            gRunTimeUsbSttings.writeTransferHandle =
909→                    USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID;
910→            gRunTimeUsbSttings.readBufferLength = 0;
911→
912→            gRunTimeUsbSttings.state = USB_CDC_STATE_INIT;
913→
914→            break;
915→        case USB_CDC_STATE_WAIT: // No action
916→        default:
917→            break;
918→    }
919→}
