233→static void Power_Up(bool enableExtPower) {
234→    
235→    /* Wait for battery management initialization with timeout
236→     * Prevents indefinite blocking if BQ24297 fails to initialize
237→     * Timeout: 5 seconds (50 x 100ms)
238→     */
239→    int initTimeout = 50;
240→    while (!pData->BQ24297Data.initComplete && initTimeout > 0) {
241→        vTaskDelay(pdMS_TO_TICKS(100));
242→        initTimeout--;
243→    }
244→    
245→    if (initTimeout == 0) {
246→        LOG_E("Power_Up: BQ24297 initialization timeout - proceeding anyway");
247→    }
248→
249→    /* Power sequencing delay - allows voltage regulators to stabilize */
250→    vTaskDelay(pdMS_TO_TICKS(50));
251→
252→    /* Enable 3.3V rail (critical - MCU power) */
253→    pWriteVariables->EN_3_3V_Val = true;
254→    Power_Write();
255→    
256→    /* 5V/10V External Power Rail Decision
257→     * Enable when:
258→     *   - User requested (enableExtPower=true) AND
259→     *   - Either external power present OR battery sufficient
260→     * Keep disabled when:
261→     *   - User wants conservation mode (enableExtPower=false) OR
262→     *   - Battery too low for safe operation
263→     */
264→    if (enableExtPower) {
265→        /* User wants external power - check if we should enable it
266→         * Use GPIO/ADC to get current status (no I2C) */
267→        Power_UpdateStatusFromGPIO();
268→        bool hasExternalPower = pData->BQ24297Data.status.pgStat;
269→
270→        if (hasExternalPower) {
271→            /* External power present - always safe to enable */
272→            pWriteVariables->EN_5_10V_Val = true;
273→        } else if (pData->chargePct >= BATT_EXT_DOWN_TH) {
274→            /* Battery has sufficient charge */
275→            pWriteVariables->EN_5_10V_Val = true;
276→        } else {
277→            /* Battery too low - don't enable external power to avoid immediate re-transition */
278→            pWriteVariables->EN_5_10V_Val = false;
279→        }
280→    } else {
281→        /* User explicitly wants external power disabled (state 2) */
282→        pWriteVariables->EN_5_10V_Val = false;
283→    }
284→    Power_Write();
285→    vTaskDelay(pdMS_TO_TICKS(50));
286→
287→    // 12V Enable (set low to turn on, set as input (or high if configured
288→    // as open collector) to turn off)
289→    pWriteVariables->EN_12V_Val = false;
290→    Power_Write();
291→    vTaskDelay(pdMS_TO_TICKS(50));
292→
293→    // Vref Enable
294→    pWriteVariables->EN_Vref_Val = true;
295→    Power_Write();
296→    vTaskDelay(pdMS_TO_TICKS(50));
297→
298→    // Set power state based on actual hardware outcome
299→    // If we requested external power but couldn't enable it due to low battery,
300→    // we should be in POWERED_UP_EXT_DOWN state to reflect reality
301→    if (enableExtPower && pWriteVariables->EN_5_10V_Val) {
302→        // External power was requested AND successfully enabled
303→        pData->powerState = POWERED_UP;
304→    } else {
305→        // External power was either not requested OR couldn't be enabled
306→        pData->powerState = POWERED_UP_EXT_DOWN;
307→    }
308→    // Don't reset requestedPowerState here - let the state machine handle it
309→}
310→
311→void Power_Down(void) {
312→    
313→    /* Disable external power rails */
314→    pWriteVariables->EN_5_10V_Val = false;   /* 5V/10V off */
315→    pWriteVariables->EN_12V_Val = true;      /* 12V off (inverted logic) */
316→    pWriteVariables->EN_Vref_Val = false;    /* ADC reference off */
317→    
318→    /* 3.3V rail handling - special case
319→     * Setting to false triggers HiZ mode in Power_Write()
320→     * This allows pulldown resistor to control the rail
321→     * Also enables button-based power control
322→     */
323→    pWriteVariables->EN_3_3V_Val = false;
324→    Power_Write();  /* Executes HiZ transition */
325→
326→    pData->powerState = STANDBY;
327→    pData->requestedPowerState = NO_CHANGE;
328→}
