static scpi_result_t SCPI_SetEcho(scpi_t * context) {
    int param1;
    microrl_t* console;
    if (!SCPI_ParamInt32(context, &param1, TRUE)) {
        return SCPI_RES_ERR;
    }
    if (param1<-1 || param1 > 1) {
        return SCPI_RES_ERR;
    }
    console = SCPI_GetMicroRLClient(context);
    if (console == NULL)
        return SCPI_RES_ERR;
    microrl_set_echo(console, param1);
    return SCPI_RES_OK;
}
