    //! From charger current control register 0x02
    uint8_t ichg;
    // From operation control register 0x07
    bool iinDet_Read;
    // From status register 0x08
    //! Bus status
    enum eBusStatus vBusStat;
    //! Charge status
    enum eChargeStatus chgStat;
    bool dpmStat;
    bool pgStat;
    bool thermStat;
    bool vsysStat;
