    bool watchdog_fault;
    bool otg_fault;
    //! Charge error
    enum eChargeFault chgFault;
    bool bat_fault;
    //! NTC Fault code
    enum eNTCFault ntcFault;
    // Inferred battery status from registers
    bool batPresent;
