497→                    // DPDM stuck after 3s — set IINLIM anyway
498→                    LOG_E("IINLIM: DPDM not complete after 3s (REG07=0x%02X), forcing 500mA",
499→                          reg07);
500→                    if (BQ24297_SetIINLIM(ILim_500)) {
501→                        pData->iinlimTimestamp = now;
502→                        pData->iinlimState = IINLIM_STATE_WAIT_USB;
503→                    } else {
504→                        LOG_E("IINLIM: Failed to set 500mA on timeout, retrying next cycle");
505→                    }
506→                }
507→            }
508→            break;
509→
510→        case IINLIM_STATE_WAIT_USB:
511→            if (!vbusPresent) {
512→                BQ24297_SetIINLIM(ILim_500);
513→                LOG_D("IINLIM: VBUS lost during WAIT_USB, reset to 500mA");
514→                pData->iinlimState = IINLIM_STATE_IDLE;
515→                break;
516→            }
517→            if ((now - pData->iinlimTimestamp) >= pdMS_TO_TICKS(2000)) {
518→                if (UsbCdc_IsConfigured()) {
519→                    // USB host enumerated — keep 500mA (USB-spec safe)
520→                    LOG_D("IINLIM: USB configured, keeping 500mA");
521→                    pData->iinlimState = IINLIM_STATE_SETTLED;
522→                } else {
523→                    // No USB enumeration — wall charger, bump to 2000mA
524→                    if (BQ24297_SetIINLIM(ILim_2000)) {
525→                        LOG_D("IINLIM: No USB config, set 2000mA (wall charger)");
526→                        pData->iinlimState = IINLIM_STATE_SETTLED;
527→                    } else {
528→                        LOG_E("IINLIM: Failed to set 2000mA, retrying next cycle");
529→                    }
530→                }
531→            }
532→            break;
533→
534→        case IINLIM_STATE_SETTLED:
535→            if (!vbusPresent) {
536→                BQ24297_SetIINLIM(ILim_500);
537→                LOG_D("IINLIM: VBUS lost, reset to 500mA");
538→                pData->iinlimState = IINLIM_STATE_IDLE;
539→            }
540→            break;
541→
542→        default:
543→            pData->iinlimState = IINLIM_STATE_IDLE;
544→            break;
545→    }
546→
547→    pData->iinlimLastVbus = vbusPresent;
548→}
