142→void Power_Tasks(void) {
143→    /* Initialize battery management if needed */
144→    if (pData->BQ24297Data.initComplete == false) {
145→        BQ24297_Config_Settings();
146→    }
147→
148→    /* Manage IINLIM state machine — runs every Power_Tasks() call (~100ms)
149→     * Detects VBUS edges and adjusts IINLIM based on USB enumeration status */
150→    if (pData->BQ24297Data.initComplete) {
151→        USBHS_VBUS_LEVEL vbusLevel = PLIB_USBHS_VBUSLevelGet(USBHS_ID_0);
152→        bool vbusPresent = (vbusLevel >= USBHS_VBUS_BELOW_VBUSVALID);
153→        BQ24297_ManageIINLIM(vbusPresent);
154→    }
155→
156→    /* Update power state at 1 second intervals */
157→    static TickType_t lastUpdateTime = 0;
158→    TickType_t currentTime = xTaskGetTickCount();
159→    if ((currentTime - lastUpdateTime) >= pdMS_TO_TICKS(1000)) {
160→        lastUpdateTime = currentTime;
161→        Power_UpdateState();
162→    }
163→}
