1031→/**
1032→ * SCPI Callback: Dump all BQ24297 registers for debugging
1033→ * Command: SYSTem:POWer:BQ:REGisters?
1034→ * Returns: All 11 registers (REG00-REG0A) in hex format with decoded fields
1035→ */
1036→static scpi_result_t SCPI_GetBQRegisters(scpi_t * context) {
1037→    // Read all registers including REG0A, tracking I2C errors (0xFF = read failure)
1038→    uint8_t regs[11];
1039→    int errCount = 0;
1040→    for (int i = 0; i < 11; i++) {
1041→        regs[i] = BQ24297_Read_I2C(i);
1042→        if (regs[i] == 0xFF) errCount++;
1043→    }
1044→
1045→    // If all reads failed, I2C bus is down
1046→    if (errCount == 11) {
1047→        scpi_printf(context, "I2C error: all register reads failed (0xFF)\r\n");
1048→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1049→        return SCPI_RES_ERR;
1050→    }
1051→
1052→    // REG00: Input Source Control
1053→    if (regs[0] == 0xFF) {
1054→        scpi_printf(context, "REG00=ERR (I2C read failed)\r\n");
1055→    } else {
1056→        scpi_printf(context, "REG00=0x%02X HIZ=%d VINDPM=%d ILIM=%d\r\n",
1057→            regs[0], (regs[0] >> 7) & 0x01, (regs[0] >> 3) & 0x0F, regs[0] & 0x07);
1058→    }
1059→
1060→    // REG01: Power-On Config
1061→    if (regs[1] == 0xFF) {
1062→        scpi_printf(context, "REG01=ERR (I2C read failed)\r\n");
1063→    } else {
1064→        scpi_printf(context, "REG01=0x%02X OTG=%d CHG=%d SYS_MIN=%d\r\n",
1065→            regs[1], (regs[1] >> 5) & 0x01, (regs[1] >> 4) & 0x01, (regs[1] >> 1) & 0x07);
1066→    }
1067→
1068→    // REG02: Charge Current Control
1069→    if (regs[2] == 0xFF) {
1070→        scpi_printf(context, "REG02=ERR (I2C read failed)\r\n");
1071→    } else {
1072→        scpi_printf(context, "REG02=0x%02X ICHG=%d BCOLD=%d\r\n",
1073→            regs[2], (regs[2] >> 2) & 0x3F, regs[2] & 0x01);
1074→    }
1075→
1076→    // REG03: Pre-Charge/Termination Current
1077→    if (regs[3] == 0xFF) {
1078→        scpi_printf(context, "REG03=ERR (I2C read failed)\r\n");
1079→    } else {
1080→        scpi_printf(context, "REG03=0x%02X IPRECHG=%d ITERM=%d\r\n",
1081→            regs[3], (regs[3] >> 4) & 0x0F, regs[3] & 0x0F);
1082→    }
1083→
1084→    // REG04: Charge Voltage Control
1085→    if (regs[4] == 0xFF) {
1086→        scpi_printf(context, "REG04=ERR (I2C read failed)\r\n");
1087→    } else {
1088→        scpi_printf(context, "REG04=0x%02X VREG=%d BATLOWV=%d VRECHG=%d\r\n",
1089→            regs[4], (regs[4] >> 2) & 0x3F, (regs[4] >> 1) & 0x01, regs[4] & 0x01);
1090→    }
1091→
1092→    // REG05: Charge Termination/Timer Control
1093→    if (regs[5] == 0xFF) {
1094→        scpi_printf(context, "REG05=ERR (I2C read failed)\r\n");
1095→    } else {
1096→        scpi_printf(context, "REG05=0x%02X EN_TERM=%d WDOG=%d EN_TIMER=%d\r\n",
1097→            regs[5], (regs[5] >> 7) & 0x01, (regs[5] >> 4) & 0x03, (regs[5] >> 3) & 0x01);
1098→    }
1099→
1100→    // REG06: Boost Voltage/Thermal Regulation
1101→    if (regs[6] == 0xFF) {
1102→        scpi_printf(context, "REG06=ERR (I2C read failed)\r\n");
1103→    } else {
1104→        scpi_printf(context, "REG06=0x%02X BOOSTV=%d BHOT=%d TREG=%d\r\n",
1105→            regs[6], (regs[6] >> 4) & 0x0F, (regs[6] >> 2) & 0x03, regs[6] & 0x03);
1106→    }
1107→
1108→    // REG07: Misc Operation Control
1109→    if (regs[7] == 0xFF) {
1110→        scpi_printf(context, "REG07=ERR (I2C read failed)\r\n");
1111→    } else {
1112→        scpi_printf(context, "REG07=0x%02X DPDM=%d TMR2X=%d BATFET=%d INT=%d\r\n",
1113→            regs[7], (regs[7] >> 7) & 0x01, (regs[7] >> 6) & 0x01,
1114→            (regs[7] >> 5) & 0x01, regs[7] & 0x03);
1115→    }
1116→
1117→    // REG08: System Status (key register for DPDM result)
1118→    if (regs[8] == 0xFF) {
1119→        scpi_printf(context, "REG08=ERR (I2C read failed)\r\n");
1120→    } else {
1121→        const char* vbusStr[] = {"Unknown", "USB_SDP", "Adapter", "OTG"};
1122→        const char* chgStr[] = {"NotChg", "PreChg", "FastChg", "Done"};
1123→        scpi_printf(context, "REG08=0x%02X VBUS=%s CHG=%s DPM=%d PG=%d THERM=%d VSYS=%d\r\n",
1124→            regs[8], vbusStr[(regs[8] >> 6) & 0x03], chgStr[(regs[8] >> 4) & 0x03],
1125→            (regs[8] >> 3) & 0x01, (regs[8] >> 2) & 0x01,
1126→            (regs[8] >> 1) & 0x01, regs[8] & 0x01);
1127→    }
1128→
1129→    // REG09: Fault Status
1130→    if (regs[9] == 0xFF) {
1131→        scpi_printf(context, "REG09=ERR (I2C read failed)\r\n");
1132→    } else {
1133→        scpi_printf(context, "REG09=0x%02X WDOG_FLT=%d OTG_FLT=%d CHG_FLT=%d BAT_FLT=%d NTC=%d\r\n",
1134→            regs[9], (regs[9] >> 7) & 0x01, (regs[9] >> 6) & 0x01,
1135→            (regs[9] >> 4) & 0x03, (regs[9] >> 3) & 0x01, regs[9] & 0x07);
1136→    }
1137→
1138→    // REG0A: Vendor/Part/Revision (read-only)
1139→    // PN[2:0] bits [7:5]: 001=BQ24296, 011=BQ24297
1140→    // Rev[2:0] bits [2:0]: device revision
1141→    if (regs[10] == 0xFF) {
1142→        scpi_printf(context, "REG0A=ERR (I2C read failed)\r\n");
1143→    } else {
1144→        uint8_t pn = (regs[10] >> 5) & 0x07;
1145→        uint8_t rev = regs[10] & 0x07;
1146→        const char* pnStr = (pn == 3) ? "BQ24297" :
1147→                             (pn == 1) ? "BQ24296" : "UNKNOWN";
1148→        scpi_printf(context, "REG0A=0x%02X PN=%d (%s) REV=%d%s\r\n",
1149→            regs[10], pn, pnStr, rev,
1150→            (pn != 3) ? " WARNING: expected BQ24297 (PN=3)" : "");
1151→    }
1152→
1153→    if (errCount > 0) {
1154→        scpi_printf(context, "WARNING: %d register(s) returned I2C error\r\n", errCount);
1155→    }
1156→
1157→    return SCPI_RES_OK;
1158→}
