1160→/**
1161→ * SCPI Callback: Set BQ24297 ILIM (input current limit)
1162→ * Command: SYSTem:POWer:BQ:ILIM <value>
1163→ * Values: 0=100mA, 1=150mA, 2=500mA, 3=900mA, 4=1A, 5=1.5A, 6=2A, 7=3A
1164→ */
1165→static scpi_result_t SCPI_SetBQILim(scpi_t * context) {
1166→    int32_t ilim;
1167→
1168→    if (!SCPI_ParamInt32(context, &ilim, TRUE)) {
1169→        return SCPI_RES_ERR;
1170→    }
1171→
1172→    if (ilim < 0 || ilim > ILim_3000) {
1173→        SCPI_ErrorPush(context, SCPI_ERROR_ILLEGAL_PARAMETER_VALUE);
1174→        return SCPI_RES_ERR;
1175→    }
1176→
1177→    bool success = BQ24297_SetIINLIM((uint8_t)ilim);
1178→    if (!success) {
1179→        LOG_E("SCPI_SetBQILim: I2C write failed for ILIM=%d", (int)ilim);
1180→        scpi_printf(context, "I2C error: write failed\r\n");
1181→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1182→        return SCPI_RES_ERR;
1183→    }
1184→
1185→    // Verify by reading back
1186→    uint8_t readback = BQ24297_Read_I2C(0x00);
1187→    if (readback == 0xFF) {
1188→        scpi_printf(context, "Write OK, readback I2C error\r\n");
1189→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1190→        return SCPI_RES_ERR;
1191→    }
1192→
1193→    uint8_t actual = readback & 0x07;
1194→    uint8_t hiz = (readback >> 7) & 0x01;
1195→    if (actual != (uint8_t)ilim || hiz != 0) {
1196→        scpi_printf(context, "Verify failed: wrote ILIM=%d, read ILIM=%d HIZ=%d (REG00=0x%02X)\r\n",
1197→                 (int)ilim, actual, hiz, readback);
1198→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1199→        return SCPI_RES_ERR;
1200→    }
1201→
1202→    scpi_printf(context, "ILIM=%d HIZ=%d Readback=0x%02X OK\r\n", actual, hiz, readback);
1203→    return SCPI_RES_OK;
1204→}
