1206→/**
1207→ * SCPI Callback: Force DPDM detection
1208→ * Command: SYSTem:POWer:BQ:DPDM
1209→ * Triggers BQ24297 to re-run D+/D- detection
1210→ */
1211→static scpi_result_t SCPI_ForceDPDM(scpi_t * context) {
1212→    // Read REG07
1213→    uint8_t reg7 = BQ24297_Read_I2C(0x07);
1214→    if (reg7 == 0xFF) {
1215→        scpi_printf(context, "I2C error: cannot read REG07\r\n");
1216→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1217→        return SCPI_RES_ERR;
1218→    }
1219→
1220→    // Set DPDM_EN bit (bit 7) to force detection
1221→    if (!BQ24297_Write_I2C(0x07, reg7 | 0x80)) {
1222→        scpi_printf(context, "I2C error: cannot write REG07\r\n");
1223→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1224→        return SCPI_RES_ERR;
1225→    }
1226→
1227→    // Wait for detection to complete (poll bit 7)
1228→    int timeout = 20;  // 2 seconds max
1229→    uint8_t status;
1230→    bool i2cOk = true;
1231→    do {
1232→        vTaskDelay(pdMS_TO_TICKS(100));
1233→        status = BQ24297_Read_I2C(0x07);
1234→        if (status == 0xFF) { i2cOk = false; break; }
1235→        timeout--;
1236→    } while ((status & 0x80) && timeout > 0);
1237→
1238→    if (!i2cOk) {
1239→        scpi_printf(context, "I2C error during DPDM polling\r\n");
1240→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1241→        return SCPI_RES_ERR;
1242→    }
1243→
1244→    if (timeout <= 0 && (status & 0x80)) {
1245→        scpi_printf(context, "DPDM timeout\r\n");
1246→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1247→        return SCPI_RES_ERR;
1248→    }
1249→
1250→    // Read result from REG08
1251→    uint8_t reg8 = BQ24297_Read_I2C(0x08);
1252→    const char* vbusStr[] = {"Unknown", "USB_SDP", "Adapter", "OTG"};
1253→
1254→    if (reg8 == 0xFF) {
1255→        scpi_printf(context, "DPDM complete but REG08 read failed\r\n");
1256→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1257→        return SCPI_RES_ERR;
1258→    }
1259→
1260→    uint8_t vbusStat = (reg8 >> 6) & 0x03;
1261→    scpi_printf(context, "DPDM complete: VBUS=%s (%d), REG08=0x%02X\r\n",
1262→             vbusStr[vbusStat], vbusStat, reg8);
1263→    return SCPI_RES_OK;
1264→}
