1266→/**
1267→ * SCPI Callback: Comprehensive BQ24297 diagnostics report
1268→ * Command: SYSTem:POWer:BQ:DIAGnostics?
1269→ * Returns: Multi-section human-readable diagnostic dump
1270→ */
1271→static scpi_result_t SCPI_GetBQDiagnostics(scpi_t * context) {
1272→    tPowerData* pPower = (tPowerData*)BoardData_Get(
1273→            BOARDDATA_POWER_DATA,
1274→            0);
1275→    tBQ24297Data* pBQ = &pPower->BQ24297Data;
1276→
1277→    // Refresh cached status from hardware
1278→    BQ24297_UpdateStatus();
1279→
1280→    // --- [Battery] ---
1281→    scpi_printf(context, "[Battery]\r\n");
1282→    scpi_printf(context, "  Voltage: %.2fV | Charge: %d%% | Low: %s\r\n",
1283→        pPower->battVoltage, pPower->chargePct,
1284→        pPower->battLow ? "Yes" : "No");
1285→    scpi_printf(context, "  Present: %s | Charge allowed: %s\r\n",
1286→        pBQ->status.batPresent ? "Yes" : "No",
1287→        pBQ->chargeAllowed ? "Yes" : "No");
1288→
1289→    // --- [BQ24297 Registers] ---
1290→    scpi_printf(context, "[BQ24297 Registers]\r\n");
1291→
1292→    // Read raw registers for fields not in status struct
1293→    uint8_t reg00 = BQ24297_Read_I2C(0x00);
1294→    uint8_t reg01 = BQ24297_Read_I2C(0x01);
1295→    uint8_t reg07 = BQ24297_Read_I2C(0x07);
1296→    uint8_t reg08 = BQ24297_Read_I2C(0x08);
1297→    uint8_t reg09 = BQ24297_Read_I2C(0x09);
1298→
1299→    const char* iinlimStr[] = {"100mA","150mA","500mA","900mA","1A","1.5A","2A","3A"};
1300→    if (reg00 == 0xFF) {
1301→        scpi_printf(context, "  REG00=ERR (I2C read failed)\r\n");
1302→    } else {
1303→        uint8_t vindpm = (reg00 >> 3) & 0x0F;
