288→void BQ24297_ChargeEnable(bool chargeEnable) {
289→    // Temporary value to hold current register value
290→    uint8_t reg = 0;
291→
292→    reg = BQ24297_Read_I2C(0x01);
293→
294→    // OTG and Charge are mutually exclusive
295→    if (reg & 0x20) {
296→        return;  // OTG is enabled, cannot modify charge state
297→    }
298→
299→    if (pData->chargeAllowed && chargeEnable && pData->status.batPresent) {
300→        // Enable charging, preserve all bits except bit 4 (charge enable)
301→        reg = (reg & 0b11101111) | 0b00010000; // Clear bit 4, then set it
302→        BQ24297_Write_I2C(0x01, reg);
303→    } else {
304→        // Disable charging, preserve all bits except bit 4 (charge enable)
305→        reg = (reg & 0b11101111); // Just clear bit 4
306→        BQ24297_Write_I2C(0x01, reg);
307→    }
308→}
