550→void BQ24297_EnableOTG(void) {
551→    // Read REG08 for safety checks
552→    uint8_t reg08 = BQ24297_Read_I2C(0x08);
553→    bool pgStat = (reg08 >> 2) & 0x01;
554→    uint8_t vbusStat = (reg08 >> 6) & 0x03;
555→    
556→    // Clear HIZ mode if active
557→    uint8_t reg00 = BQ24297_Read_I2C(0x00);
558→    if (reg00 & 0x80) {
559→        reg00 &= 0x7F;  // Clear bit 7 (HIZ)
560→        BQ24297_Write_I2C(0x00, reg00);
561→        vTaskDelay(5 / portTICK_PERIOD_MS);
562→    }
563→    
564→    // Cannot enable OTG if external power is present
565→    if (pgStat) {
566→        return;
567→    }
568→    
569→    // Check if OTG is already active
570→    if (vbusStat == 0x03) {
571→        uint8_t reg01 = BQ24297_Read_I2C(0x01);
572→        if (reg01 & 0x20) {
573→            pData->status.otg = true;
574→            pData->status.chgEn = false;
575→            return;
576→        }
577→    }
578→    
579→    // Set OTG GPIO HIGH to enable boost mode
580→    BATT_MAN_OTG_OutputEnable();
581→    BATT_MAN_OTG_Set();
582→    
583→    // Read current REG01 value
584→    uint8_t reg01 = BQ24297_Read_I2C(0x01);
585→    if (reg01 == 0xFF) {
586→        return;
587→    }
588→    
589→    // Configure REG01 for OTG mode
590→    // Bit 5 = 1 (OTG enable), Bit 4 = 0 (charge disable), Bit 6 = 1 (watchdog reset)
591→    reg01 = (reg01 & 0x0F) | 0x60;
592→    
593→    // Write with retry logic
594→    bool success = false;
595→    for (int retry = 0; retry < 3; retry++) {
596→        if (BQ24297_Write_I2C(0x01, reg01)) {
597→            vTaskDelay(5 / portTICK_PERIOD_MS);
598→            
599→            // Verify write
600→            uint8_t readback = BQ24297_Read_I2C(0x01);
601→            if ((readback & 0x30) == 0x20) {  // Check OTG=1, CHG=0
602→                success = true;
603→                break;
604→            }
605→        }
606→        vTaskDelay(10 / portTICK_PERIOD_MS);
607→    }
608→    
609→    if (!success) {
610→        BATT_MAN_OTG_Clear();  // Clear GPIO on failure
611→    }
612→    
613→    // Update status
614→    pData->status.otg = success;
615→    pData->status.chgEn = false;
616→}
