 59→/* Battery Management Thresholds
 60→ * - BATT_EXT_DOWN_TH (15%): Below this, external power rails disabled to conserve battery
 61→ * - BATT_LOW_TH (5%): Critical level - device must shut down
 62→ * - BATT_HYST (10%): Hysteresis prevents oscillation at threshold boundaries
 63→ */
 64→#define BATT_EXT_DOWN_TH 15.0  /* External power disabled below this */
 65→#define BATT_LOW_TH 5.0        /* Critical shutdown threshold */
 66→#define BATT_HYST 10.0         /* Must charge 10% above threshold to re-enable */ 
