169→void Power_Write(void) {
170→    // Current power state values
171→
172→    bool EN_3_3V_Val_Current;
173→    bool EN_5_10V_Val_Current;
174→    bool EN_12V_Val_Current;
175→    bool EN_Vref_Val_Current;
176→
177→    EN_3_3V_Val_Current = ReadGpioPinStateLatched(pConfig->EN_3_3V_Ch, pConfig->EN_3_3V_Bit);
178→    EN_5_10V_Val_Current = ReadGpioPinStateLatched(pConfig->EN_5_10V_Ch, pConfig->EN_5_10V_Bit);
179→    EN_12V_Val_Current = ReadGpioPinStateLatched(pConfig->EN_12V_Ch, pConfig->EN_12V_Bit);
180→    EN_Vref_Val_Current = ReadGpioPinStateLatched(pConfig->EN_Vref_Ch, pConfig->EN_Vref_Bit);
181→
182→    // Check to see if we are changing the state of this power pin
183→    if (EN_3_3V_Val_Current != pWriteVariables->EN_3_3V_Val) {
184→        
185→        // CRITICAL: Only drive HIGH or set as INPUT (HiZ) - never drive LOW
186→        // There's a pulldown resistor that will drop the line when in HiZ
187→        if (pWriteVariables->EN_3_3V_Val) {
188→            // Set as OUTPUT and drive high to enable 3.3V
189→            PWR_3_3V_EN_OutputEnable();
190→            PWR_3_3V_EN_Set();
191→        } else {
192→            // Set as INPUT (HiZ) to disable - pulldown will handle the rest
193→            // Never actively drive low to avoid conflicts
194→            PWR_3_3V_EN_InputEnable();
195→        }
196→        
197→    }
198→
199→    // Check to see if we are changing the state of these power pins
200→    if (EN_5_10V_Val_Current != pWriteVariables->EN_5_10V_Val) {
201→        // PWR_5V_EN uses Port D, bit 0
202→        if (pWriteVariables->EN_5_10V_Val) {
203→            PWR_5V_EN_OutputEnable();
204→            PWR_5V_EN_Set();
205→        } else {
206→            PWR_5V_EN_Clear();
207→        }
208→    }
209→    
210→    if (EN_12V_Val_Current != pWriteVariables->EN_12V_Val) {
211→        // PWR_12V_EN uses Port H, bit 15
212→        if (pWriteVariables->EN_12V_Val) {
213→            PWR_12V_EN_OutputEnable();
214→            PWR_12V_EN_Set();
215→        } else {
216→            PWR_12V_EN_Clear();
217→        }
218→    }
219→
220→    // Check to see if we are changing the state of this power pin
221→    if (EN_Vref_Val_Current != pWriteVariables->EN_Vref_Val) {
222→        // PWR_VREF_EN uses Port J, bit 15
223→        if (pWriteVariables->EN_Vref_Val) {
224→            PWR_VREF_EN_OutputEnable();
225→            PWR_VREF_EN_Set();
226→        } else {
227→            PWR_VREF_EN_Clear();
228→        }
229→    }
230→
231→}
