330→/*
331→ * Update power status from GPIO and ADC (no I2C)
332→ *
333→ * Replaces I2C polling with:
334→ *   - USB VBUS detection for external power (pgStat equivalent)
335→ *   - ADC battery voltage for vsysStat equivalent
336→ *   - BATT_MAN_STAT GPIO for charging status
337→ *
338→ * This eliminates I2C bus hang risk during normal operation.
339→ * The previous I2C polling (~70 reads/sec on USB power) caused intermittent
340→ * hangs in PowerAndUITask, leading to LED unresponsiveness (issue #172).
341→ *
342→ * Future: Issue #173 tracks adding interrupt-driven I2C for scenarios that
343→ * require BQ24297 register access (config changes, detailed diagnostics).
344→ */
345→static void Power_UpdateStatusFromGPIO(void) {
346→    /* Update battery voltage and charge percentage from ADC */
347→    Power_UpdateChgPct();
348→
349→    /* Update external power status from hardware VBUS detection
350→     * Read directly from USB hardware register - more reliable than software events
351→     * which may not trigger correctly for wall chargers without USB data lines.
352→     *
353→     * Use USBHS_VBUS_BELOW_VBUSVALID threshold (~4.0V) instead of USBHS_VBUS_VALID
354→     * (~4.75V) to handle wall chargers with minor voltage sag. This aligns better
355→     * with BQ24297's pgStat threshold (3.88V) for external power detection. */
356→    USBHS_VBUS_LEVEL vbusLevel = PLIB_USBHS_VBUSLevelGet(USBHS_ID_0);
357→    bool hasExternalPower = (vbusLevel >= USBHS_VBUS_BELOW_VBUSVALID);
358→    pData->BQ24297Data.status.pgStat = hasExternalPower;
359→
360→    /* Update vsysStat equivalent from ADC battery voltage
361→     * vsysStat=1 means battery < 3.0V (VSYSMIN threshold) */
362→    pData->BQ24297Data.status.vsysStat = (pData->battVoltage < 3.0f);
363→
364→    /* Read charging status from BATT_MAN_STAT GPIO
365→     * BQ24297 STAT pin: LOW = charging, HIGH = not charging/complete
366→     * Map to chgStat: 0=not charging, 1=pre-charge, 2=fast charge, 3=done */
367→    bool isCharging = !BATT_MAN_STAT_Get();  /* Active low */
368→    if (isCharging) {
369→        pData->BQ24297Data.status.chgStat = 2;  /* Fast charging */
370→    } else if (hasExternalPower && pData->chargePct >= 95.0f) {
371→        pData->BQ24297Data.status.chgStat = 3;  /* Charge complete */
372→    } else {
373→        pData->BQ24297Data.status.chgStat = 0;  /* Not charging */
374→    }
375→
376→    /* Update external power source type
377→     * Without I2C, we can't distinguish USB types, so assume USB 500mA when VBUS present */
378→    if (hasExternalPower) {
379→        pData->externalPowerSource = USB_500MA_EXT_POWER;
380→    } else {
381→        pData->externalPowerSource = NO_EXT_POWER;
382→    }
383→}
384→
385→/*
386→ * Rate-limited status update helper
387→ * Uses GPIO and ADC instead of I2C to avoid bus hang risk
388→ *
389→ * @param updateIntervalMs Minimum time between updates (ms)
390→ * @param lastUpdateTime Pointer to timestamp of last update
391→ * @return true if update performed, false if rate-limited
392→ */
393→static bool Power_UpdateStatusIfNeeded(uint32_t updateIntervalMs, TickType_t* lastUpdateTime) {
394→    TickType_t currentTime = xTaskGetTickCount();
395→    if ((currentTime - *lastUpdateTime) >= pdMS_TO_TICKS(updateIntervalMs)) {
396→        *lastUpdateTime = currentTime;
397→        Power_UpdateStatusFromGPIO();
398→        return true;
399→    }
400→    return false;
401→}
