403→/*
404→ * Check if system has sufficient power to operate
405→ * Returns true if:
406→ *   - Battery voltage > 3.0V (vsysStat = 0) OR
407→ *   - External power present (pgStat = 1)
408→ */
409→static bool Power_HasSufficientPower(void) {
410→    return (!pData->BQ24297Data.status.vsysStat || pData->BQ24297Data.status.pgStat);
411→}
412→
413→/*
414→ * STANDBY State Handler
415→ * 
416→ * Responsibilities:
417→ *   - Process power-up requests from user
418→ *   - Execute power-down sequence when needed
419→ *   - Monitor battery and external power
420→ *   - Update status (faster on USB for button response)
421→ */
422→static void Power_HandleStandbyState(void) {
423→    /* Priority 1: Handle user power-up requests */
424→    if (pData->requestedPowerState == DO_POWER_UP ||
425→        pData->requestedPowerState == DO_POWER_UP_EXT_DOWN) {
426→
427→        /* Refresh power status from GPIO/ADC before power-up decision */
428→        Power_UpdateStatusFromGPIO();
429→
430→        if (Power_HasSufficientPower()) {
431→            // Power up with or without external power based on request
432→            bool enableExtPower = (pData->requestedPowerState == DO_POWER_UP);
433→            Power_Up(enableExtPower);
434→            pData->requestedPowerState = NO_CHANGE;
435→            return;
436→        } else {
437→            // Insufficient power for power-up request
438→            LOG_D("Power_UpdateState: Insufficient power - battery < 3.0V and no external power");
439→            pData->shutdownNotified = false;
440→            pData->requestedPowerState = NO_CHANGE;
441→        }
442→    }
443→    
444→    /* Execute power-down sequence (one-shot flag)
445→     * shutdownNotified is set by UI task after LED warning sequence completes
446→     * This ensures user is notified before shutdown */
447→    if (pData->shutdownNotified == true) {
448→        Power_Down();
449→        pData->shutdownNotified = false;  /* Clear flag to prevent repeated calls */
450→        
451→        /* Exit early on battery to conserve power */
452→        if (!pData->BQ24297Data.status.pgStat) {
453→            return;
454→        }
455→    }
456→    
457→    /* Status update with adaptive rate
458→     * - 100ms on USB: Better button/command responsiveness
459→     * - 1000ms on battery: Conserve power
460→     */
461→    static TickType_t lastStandbyUpdate = 0;
462→    uint32_t updateInterval = pData->BQ24297Data.status.pgStat ? 100 : 1000;
463→    if (Power_UpdateStatusIfNeeded(updateInterval, &lastStandbyUpdate)) {
464→        Power_Update_Settings();
465→    }
466→}
467→
468→/*
469→ * POWERED_UP State Handler
470→ * 
471→ * All power rails enabled, monitoring for:
472→ *   - Battery drops below conservation threshold (15%)
473→ *   - User requests for state changes
474→ *   - Regular status updates
475→ */
476→static void Power_HandlePoweredUpState(void) {
477→    /* Clear redundant request (already in this state) */
478→    if (pData->requestedPowerState == DO_POWER_UP) {
479→        pData->requestedPowerState = NO_CHANGE;
480→    }
481→    
482→    // Rate limit status updates
483→    static TickType_t lastStatusUpdate = 0;
484→    if (Power_UpdateStatusIfNeeded(1000, &lastStatusUpdate)) {
485→        Power_Update_Settings();
486→    }
487→    
488→    bool hasExternalPower = pData->BQ24297Data.status.pgStat;
489→    
490→    /* User-requested transition to conservation mode */
491→    if (pData->requestedPowerState == DO_POWER_UP_EXT_DOWN) {
492→        pWriteVariables->EN_5_10V_Val = false;
493→        Power_Write();
494→        pData->powerState = POWERED_UP_EXT_DOWN;
495→        pData->requestedPowerState = NO_CHANGE;
496→    }
497→    /* Automatic transition when battery needs conservation */
498→    else if (!hasExternalPower) {
499→        /* Refresh power status from GPIO/ADC before threshold decision */
500→        Power_UpdateStatusFromGPIO();
501→
502→        if (pData->chargePct < BATT_EXT_DOWN_TH) {
503→            LOG_D("Power_UpdateState: Battery at %u%%, transitioning to POWERED_UP_EXT_DOWN to conserve power",
504→                  pData->chargePct);
505→            pWriteVariables->EN_5_10V_Val = false;
506→            Power_Write();
507→            pData->powerState = POWERED_UP_EXT_DOWN;
508→        }
509→    }
510→}
511→
512→/*
513→ * POWERED_UP_EXT_DOWN State Handler (Conservation Mode)
514→ * 
515→ * Core system powered, external rails disabled to save battery
516→ * Monitoring for:
517→ *   - Battery recovery (charge > 25% with hysteresis)
518→ *   - External power connection
519→ *   - Critical battery level (<5%)
520→ */
521→static void Power_HandlePoweredUpExtDownState(void) {
522→    /* Rate limit status updates - uses GPIO/ADC, no I2C */
523→    static TickType_t lastExtDownUpdate = 0;
524→    Power_UpdateStatusIfNeeded(1000, &lastExtDownUpdate);
525→
526→    bool hasExternalPower = pData->BQ24297Data.status.pgStat;
527→
528→    /* Check for automatic recovery if auto external power control is enabled */
529→    if (pData->autoExtPowerEnabled) {
530→        /* Check recovery conditions (with hysteresis to prevent oscillation) */
531→        if (hasExternalPower || pData->chargePct >= (BATT_EXT_DOWN_TH + BATT_HYST)) {
532→            /* Auto-recovery - re-enable external power */
533→            LOG_D("Auto-recovery: Enabling external power - %s, battery at %u%%",
534→                  hasExternalPower ? "external power present" : "battery recovered", pData->chargePct);
535→            pWriteVariables->EN_5_10V_Val = true;
536→            Power_Write();
537→            pData->powerState = POWERED_UP;
538→            return;  /* Exit early after state change */
539→        }
540→    }
541→
542→    /* Handle user power state change requests */
543→    if (pData->requestedPowerState == DO_POWER_UP) {
544→        /* Refresh power status from GPIO/ADC before decision */
545→        Power_UpdateStatusFromGPIO();
546→        hasExternalPower = pData->BQ24297Data.status.pgStat;
547→
548→        /* Check recovery conditions (with hysteresis to prevent oscillation) */
549→        if (hasExternalPower || pData->chargePct >= (BATT_EXT_DOWN_TH + BATT_HYST)) {
550→            /* Manual recovery - re-enable external power */
551→            LOG_D("Manual recovery: Enabling external power - %s, battery at %u%%",
552→                  hasExternalPower ? "external power present" : "battery sufficient", pData->chargePct);
553→            pWriteVariables->EN_5_10V_Val = true;
554→            Power_Write();
555→            pData->powerState = POWERED_UP;
556→        } else {
557→            /* Cannot enable external power due to low battery */
558→            LOG_D("Power_HandlePoweredUpExtDownState: Cannot enable external power - battery at %u%%, needs %u%%",
559→                  pData->chargePct, (unsigned)(BATT_EXT_DOWN_TH + BATT_HYST));
560→        }
561→        pData->requestedPowerState = NO_CHANGE;
562→    }
563→    /* Critical battery check - must shut down to prevent damage */
564→    else if (!hasExternalPower && pData->chargePct < BATT_LOW_TH) {
565→        LOG_D("Power_UpdateState: Battery critically low (%u%%), transitioning to STANDBY",
566→              pData->chargePct);
567→
568→        /* Explicitly disable all external rails before shutdown */
569→        pWriteVariables->EN_5_10V_Val = false;
570→        pWriteVariables->EN_12V_Val = true;     /* Inverted logic - true = off */
571→        pWriteVariables->EN_Vref_Val = false;
572→        Power_Write();
573→
574→        pData->shutdownNotified = false;
575→        pData->powerState = STANDBY;
576→    }
577→}
578→
579→/*
580→ * Main Power State Machine
581→ * 
582→ * State transitions:
583→ *   STANDBY -> POWERED_UP: User request with sufficient power
584→ *   POWERED_UP -> POWERED_UP_EXT_DOWN: Battery < 15% or user request
585→ *   POWERED_UP_EXT_DOWN -> POWERED_UP: Battery > 25% or external power
586→ *   POWERED_UP_EXT_DOWN -> STANDBY: Battery < 5% (critical)
587→ *   Any state -> STANDBY: User power-down request
588→ */
589→static void Power_UpdateState(void) {
590→    static POWER_STATE lastLoggedState = -1;
591→    
592→    /* Monitor 3.3V rail state (debug/diagnostic) */
593→    static bool last3v3State = false;
594→    static bool first3v3Check = true;
595→    bool current3v3State = ReadGpioPinStateLatched(pConfig->EN_3_3V_Ch, pConfig->EN_3_3V_Bit);
596→    
597→    if (first3v3Check || (current3v3State != last3v3State)) {
598→        last3v3State = current3v3State;
599→        first3v3Check = false;
600→    }
601→    
602→    // Log state changes
603→    if (pData->powerState != lastLoggedState) {
604→        LOG_D("Power_UpdateState: State changed from %d to %d", lastLoggedState, pData->powerState);
605→        lastLoggedState = pData->powerState;
606→    }
607→    
608→    /* Common handler: Power-down request (works in any state) */
609→    if (pData->requestedPowerState == DO_POWER_DOWN) {
610→        pData->powerState = STANDBY;
611→        pData->requestedPowerState = NO_CHANGE;
612→        /* Note: Actual power-down executed by STANDBY handler */
613→    }
614→    
615→    /* Delegate to state-specific handlers */
616→    switch (pData->powerState) {
617→        case STANDBY:
618→            Power_HandleStandbyState();
619→            break;
620→            
621→        case POWERED_UP:
622→            Power_HandlePoweredUpState();
623→            break;
624→            
625→        case POWERED_UP_EXT_DOWN:
626→            Power_HandlePoweredUpExtDownState();
627→            break;
628→            
629→        default:
630→            LOG_E("Power_UpdateState: Unknown power state %d", pData->powerState);
631→            break;
632→    }
633→
634→}
