636→static void Power_UpdateChgPct(void) {
637→    /* Read battery voltage from ADC */
638→    size_t index = ADC_FindChannelIndex(ADC_CHANNEL_VBATT);
639→    const AInSample *pAnalogSample = BoardData_Get(
640→            BOARDDATA_AIN_LATEST,
641→            index);
642→    if (NULL != pAnalogSample) {
643→        float newVoltage = ADC_ConvertToVoltage(pAnalogSample);
644→        /* Validate reading (ignore noise near 0V) */
645→        if (newVoltage > 0.1) {
646→            pData->battVoltage = newVoltage;
647→        }
648→    }
649→
650→    /* Convert voltage to percentage using linear approximation
651→     * Valid range: 3.17V (0%) to 3.868V (100%)
652→     * Formula: percentage = 142.92 * voltage - 452.93
653→     */
654→    if (pData->battVoltage < 3.17) {
655→        pData->chargePct = 0;
656→    } else if (pData->battVoltage > 3.868) {
657→        pData->chargePct = 100;
658→    } else {
659→        pData->chargePct = 142.92 * pData->battVoltage - 452.93;
660→    }
661→}
