 31→void BQ24297_InitHardware(                                                  
 32→                        tBQ24297Config *pConfigInit,                        
 33→                        tBQ24297WriteVars *pWriteInit,                      
 34→                        tBQ24297Data *pDataInit) {
 35→    pConfigBQ24 = pConfigInit;
 36→    pWriteVariables = pWriteInit;
 37→    pData = pDataInit;
 38→
 39→    // Battery management initialization (hardware interface)
 40→
 41→    // ***Disable I2C calls*** as Harmony 2.06 doesn't have a working, 
 42→    // interrupt-safe implementation
 43→    // Open the I2C Driver for Master
 44→    pData->I2C_Handle = DRV_I2C_Open(                                       
 45→                        pConfigBQ24->I2C_Index,                             
 46→                        DRV_IO_INTENT_READWRITE|DRV_IO_INTENT_BLOCKING);
 47→
 48→    // Drive OTG LOW — DPDM will set 100mA (conservative).
 49→    // ManageIINLIM state machine overrides IINLIM via I2C after DPDM completes.
 50→    BATT_MAN_OTG_OutputEnable();
 51→    BATT_MAN_OTG_Clear();
 52→}
