 54→void BQ24297_Config_Settings(void) {
 55→    // Temporary value to hold current register value
 56→    uint8_t reg = 0;
 57→    
 58→    LOG_D("BQ24297_Config_Settings: Starting initialization");
 59→    
 60→    // Read initial status to determine current power state
 61→    BQ24297_UpdateStatus();
 62→
 63→    // Read REG00 to preserve current limit settings
 64→    reg = BQ24297_Read_I2C(0x00);
 65→    
 66→    // Clear HIZ mode if set - it can cause power loss
 67→    if (reg & 0x80) {
 68→        LOG_D("BQ24297_Config_Settings: Clearing HIZ mode");
 69→    }
 70→
 71→    // Set input voltage limit to 3.88V (minimum): VINDPM = 0
 72→    // This gives maximum headroom before input voltage regulation kicks in
 73→    // REG00: [7]=0 (CLEAR HIZ), [6:3]=0000 (3.88V min), [2:0]=keep current limit
 74→    BQ24297_Write_I2C(0x00, reg & 0b00000111);  // This also clears HIZ bit
 75→
 76→    // Configure REG01 for charging mode
 77→    // REG01 bits:
 78→    // [7:6] = 01 (reset watchdog)
 79→    // [5] = 0 (OTG disable)
 80→    // [4] = 1 (CHARGE ENABLE)
 81→    // [3:1] = 000 (SYS_MIN = 3.0V)
 82→    // [0] = 1 (reserved)
 83→    
 84→    // Drive OTG LOW — DPDM sets 100mA (conservative), ManageIINLIM overrides via I2C
 85→    BATT_MAN_OTG_OutputEnable();
 86→    BATT_MAN_OTG_Clear();
 87→
 88→    // Configure for charge mode with SYS_MIN=3.0V to prevent BATFET disable
 89→    BQ24297_Write_I2C(0x01, 0b01010001);  // Watchdog reset, OTG=0, CHG=1, SYS_MIN=3.0V
 90→
 91→    // Set fast charge to 2000mA - this should never need to be updated
 92→    BQ24297_Write_I2C(0x02, 0b01100000);
 93→    
 94→    // REG03: Pre-charge and termination current
 95→    // Set minimum termination current (128mA) to avoid premature termination
 96→    // [7:5]=000 (128mA precharge), [4]=0 (reserved), [3:0]=0001 (128mA termination)
 97→    BQ24297_Write_I2C(0x03, 0b00000001);
 98→
 99→    // REG04: Charge voltage and battery thresholds
100→    // [7:2]=100101 (4.096V), [1]=1 (3.0V battery low), [0]=0 (100mV recharge)
101→    // Set BATLOWV to 3.0V (higher threshold) to keep BATFET enabled longer
102→    BQ24297_Write_I2C(0x04, 0b10010110);
103→
104→    // REG05: Disable watchdog and maximize charge timer
105→    // [7]=1 (enable termination), [6]=0 (disable timer), [5:4]=00 (disable watchdog)
106→    // [3]=0 (normal), [2:1]=11 (20hr timer), [0]=0 (reserved)
107→    // CRITICAL: Watchdog disabled to prevent unexpected BATFET disable
108→    BQ24297_Write_I2C(0x05, 0b10001110);
109→    
110→    // REG06: Boost voltage and thermal regulation
111→    // [7:4]=0111 (4.998V boost), [3:2]=00 (reserved), [1:0]=11 (120C thermal limit)
112→    // Keep default boost voltage but set highest thermal limit
113→    BQ24297_Write_I2C(0x06, 0b01110011);
114→    
115→    // Ensure BATFET is enabled (REG07 bit 5 = 0)
116→    // Without BATFET, there's no path from battery to system
117→    reg = BQ24297_Read_I2C(0x07);
118→    if (reg & 0b00100000) {  // Check if bit 5 is set (BATFET disabled)
119→        reg = reg & 0b11011111;  // Clear bit 5 to enable BATFET
120→        BQ24297_Write_I2C(0x07, reg);
121→        LOG_D("BQ24297: BATFET re-enabled");
122→    }
123→
124→    // Read the current status
125→    BQ24297_UpdateStatus();
126→
127→    // Start with conservative 500mA IINLIM
128→    // BQ24297_ManageIINLIM() state machine will adjust based on USB enumeration
129→    BQ24297_SetIINLIM(ILim_500);
130→    pData->iinlimState = IINLIM_STATE_IDLE;
131→    pData->iinlimTimestamp = 0;
132→    pData->iinlimLastVbus = false;
133→
134→    // Update battery presence status (for reporting only)
135→    BQ24297_UpdateBatteryStatus();
136→
137→    // Charging is always enabled via REG01 configuration above.
138→    // The BQ24297 has built-in hardware protection for:
139→    // - Battery temperature (NTC monitoring)
140→    // - Overvoltage/overcurrent
141→    // - Battery presence detection
142→    // Let the hardware handle charging decisions autonomously.
143→
144→    // Mark initialization complete
145→    pData->initComplete = true;
146→    
147→    LOG_D("BQ24297_Config_Settings: Initialization complete");
148→}
