290→void BQ24297_AutoSetILim(void) {
291→    // Temporary value to hold current register value
292→    uint8_t reg0;
293→
294→    reg0 = BQ24297_Read_I2C(0x00);
295→    
296→    // Log if HIZ mode is detected during AutoSetILim
297→    if (reg0 & 0x80) {
298→        LOG_E("BQ24297_AutoSetILim: WARNING - HIZ mode detected (REG00=0x%02X)! Will be cleared.", reg0);
299→    }
300→
301→    //  Set system input current
302→    // CRITICAL: Never preserve HIZ bit (bit 7) when writing to REG00!
303→    // Use mask 0b01111000 instead of 0b11111000 to clear HIZ
304→    switch (pData->status.vBusStat) {
305→        case 0b00:
306→            // Unknown - assume it is a charger. Set IINLIM to 2000mA       
307→            //- maximum allowed on charger
308→            BQ24297_Write_I2C(0x00, 0b00000110 | (reg0 & 0b01111000));
309→            break;
310→        case 0b01:
311→            // NOTE: Originally set to 500mA for USB 2.0 compliance, but this
312→            // caused audible whining from the power supply. Using 2A instead.
313→            // Most modern USB ports can handle this, especially with enumeration.
314→            // Original 500mA setting:
315→            // BQ24297_Write_I2C(0x00, 0b00000010 | (reg0 & 0b01111000));
316→            BQ24297_Write_I2C(0x00, 0b00000110 | (reg0 & 0b01111000));
317→            break;
318→        case 0b10:
319→            // Unknown - assume it is a charger. Set IINLIM to 2000mA 
320→            //maximum allowed on charger
321→            BQ24297_Write_I2C(0x00, 0b00000110 | (reg0 & 0b01111000));
322→            break;
323→        default:
324→            break;
325→    }
326→}
