328→uint8_t BQ24297_Read_I2C(uint8_t reg) {
329→    uint8_t I2CData[1];
330→    uint8_t rxData = 0;
331→
332→    // Build data packet
333→    I2CData[0] = reg;
334→
335→    if (pData->I2C_Handle != DRV_HANDLE_INVALID) {
336→        // Perform I2C transfer with error checking
337→        bool success = DRV_I2C_WriteReadTransfer(pData->I2C_Handle,
338→                pConfigBQ24->I2C_Address,
339→                I2CData,
340→                1,
341→                &rxData,
342→                1);
343→
344→        if (!success) {
345→            LOG_E("BQ24297_Read_I2C: Failed to read register 0x%02X", reg);
346→            // Return 0xFF to indicate error (distinguishable from valid data)
347→            return 0xFF;
348→        }
349→    } else {
350→        LOG_E("BQ24297_Read_I2C: Invalid I2C handle");
351→        return 0xFF;
352→    }
353→    return rxData;
354→}
355→
356→bool BQ24297_Write_I2C(uint8_t reg, uint8_t txData) {
357→    uint8_t I2CData[2];
358→
359→    // Build data packet
360→    I2CData[0] = reg;
361→    I2CData[1] = txData;
362→
363→    if (pData->I2C_Handle != DRV_HANDLE_INVALID) {
364→        // Write to selected register with error checking
365→        bool success = DRV_I2C_WriteTransfer(
366→                        pData->I2C_Handle,
367→                        pConfigBQ24->I2C_Address,
368→                        I2CData,
369→                        2);
370→
371→        if (!success) {
372→            LOG_E("BQ24297_Write_I2C: Failed to write 0x%02X to register 0x%02X", txData, reg);
373→            return false;
374→        }
375→        return true;
376→    } else {
377→        LOG_E("BQ24297_Write_I2C: Invalid I2C handle");
378→        return false;
379→    }
380→}
