625→bool BQ24297_IsBatteryPresent(void) {
626→    // Battery detection logic:
627→    // 1. If thermistor reads COLD (open circuit), battery is disconnected
628→    // 2. If thermistor reads HOT, it's stuck low (shorted) - battery may be present but charging unsafe
629→    // 3. Normal thermistor AND voltage > 3.0V indicates battery present
630→    
631→    // Update status to get latest NTC and voltage readings
632→    BQ24297_UpdateStatus();
633→    
634→    // NTC_FAULT_COLD (2) = thermistor open = no battery
635→    if (pData->status.ntcFault == NTC_FAULT_COLD) {
636→        return false;
637→    }
638→    
639→    // NTC_FAULT_HOT (1) = thermistor shorted/stuck low - unsafe to charge
640→    if (pData->status.ntcFault == NTC_FAULT_HOT) {
641→        // Battery might be present but thermistor is faulty
642→        // Check voltage to confirm battery presence
643→        return !pData->status.vsysStat;  // Battery present if voltage > 3.0V
644→    }
645→    
646→    // Normal thermistor reading - battery is present
647→    return true;
648→}
