650→void BQ24297_UpdateBatteryStatus(void) {
651→    bool oldBatPresent = pData->status.batPresent;
652→    bool oldChargeAllowed = pData->chargeAllowed;
653→
654→    pData->status.batPresent = BQ24297_IsBatteryPresent();
655→    pData->chargeAllowed = pData->status.batPresent &&
656→                           (pData->status.ntcFault != NTC_FAULT_HOT);
657→
658→    // Enforce charge state via I2C when chargeAllowed changes
659→    if (pData->chargeAllowed != oldChargeAllowed) {
660→        BQ24297_ChargeEnable(pData->chargeAllowed);
661→        LOG_D("BQ24297: Charging %s",
662→              pData->chargeAllowed ? "enabled" : "disabled");
663→    }
664→
665→    if (oldBatPresent != pData->status.batPresent) {
666→        LOG_D("BQ24297: Battery %s",
667→              pData->status.batPresent ? "detected" : "not detected");
668→    }
669→}
