162→void sd_card_manager_DataReadyCB(sd_card_manager_mode_t mode, uint8_t *pDataBuff, size_t dataLen) {
163→    // Defensive checks
164→    if (pDataBuff == NULL || dataLen == 0) {
165→        return;
166→    }
167→
168→    size_t transferredLength = 0;
169→    uint32_t retryCount = 0;
170→
171→    while (transferredLength < dataLen) {
172→        size_t remaining = dataLen - transferredLength;
173→        size_t toSend = (remaining < USB_TRANSFER_CHUNK_SIZE) ? remaining : USB_TRANSFER_CHUNK_SIZE;
174→
175→        size_t bytesWritten = UsbCdc_WriteToBuffer(
176→                NULL,
177→                (const char *) pDataBuff + transferredLength,
178→                toSend
179→                );
180→
181→        if (bytesWritten > 0) {
182→            transferredLength += bytesWritten;
183→            retryCount = 0;
184→            // If partial write, yield to let USB drain before retrying
185→            if (bytesWritten < toSend) {
186→                vTaskDelay(1);
187→            }
188→        } else {
189→            retryCount++;
190→            if (retryCount >= USB_TRANSFER_MAX_RETRIES) {
191→                LOG_E("[USB] Callback timeout: sent %u/%u bytes after %u retries",
192→                      (unsigned)transferredLength, (unsigned)dataLen, (unsigned)retryCount);
193→                break;
194→            }
195→            vTaskDelay(1);
196→        }
197→    }
198→
199→    if (transferredLength < dataLen) {
200→        LOG_E("[USB] Incomplete transfer: sent %u/%u bytes",
201→              (unsigned)transferredLength, (unsigned)dataLen);
202→    }
203→}
