219→static void app_WifiTask(void* p_arg) {
220→    // Enable FPU context saving - WiFi task processes streaming data with voltage conversion
221→    portTASK_USES_FLOATING_POINT();
222→    enum{
223→        APP_WIFI_STATE_WAIT_POWER_UP=0,
224→        APP_WIFI_STATE_PROCESS=1,
225→    };
226→    const tPowerData *pPowerState=BoardData_Get(BOARDDATA_POWER_DATA,0);
227→    uint8_t state = APP_WIFI_STATE_WAIT_POWER_UP;
228→    while (1) {     
229→        switch (state) {
230→            case APP_WIFI_STATE_WAIT_POWER_UP:
231→            {
232→                if (NULL != pPowerState &&
233→                        pPowerState->powerState != POWERED_UP &&
234→                        pPowerState->powerState != POWERED_UP_EXT_DOWN) {
235→                    state = APP_WIFI_STATE_WAIT_POWER_UP;
236→                } else {
237→                    wifi_manager_Init(&gpBoardData->wifiSettings);
238→                    state = APP_WIFI_STATE_PROCESS;
239→                }
240→            }
241→                break;
242→            case APP_WIFI_STATE_PROCESS:
243→            {
244→                wifi_manager_ProcessState();
245→                if (NULL != pPowerState &&
246→                        pPowerState->powerState != POWERED_UP &&
247→                        pPowerState->powerState != POWERED_UP_EXT_DOWN) {
248→                    wifi_manager_Deinit();
249→                    state = APP_WIFI_STATE_WAIT_POWER_UP;
250→                }
251→            }
252→                break;
253→        }
254→        vTaskDelay(5 / portTICK_PERIOD_MS);  
255→    }
256→}
