258→/**
259→ * SD Card Task
260→ * 
261→ * Manages SD card operations with intelligent SPI bus coordination.
262→ * Avoids SD operations during WiFi streaming to prevent SPI bus contention
263→ * that was causing WiFi streaming failures every ~590 seconds.
264→ */
265→static void app_SDCardTask(void* p_arg) {
266→    sd_card_manager_Init(&gpBoardRuntimeConfig->sdCardConfig);
267→    while (1) {
268→        // Critical fix: Prevent SPI bus contention between WiFi streaming/firmware update and SD operations
269→        // Background: SD operations every 1ms were causing WiFi streaming failures at ~590 seconds
270→        // Solution: Suspend SD operations during WiFi streaming AND firmware update mode for exclusive SPI access
271→        StreamingRuntimeConfig* pStreamConfig = BoardRunTimeConfig_Get(BOARDRUNTIME_STREAMING_CONFIGURATION);
272→        bool isStreaming = (pStreamConfig != NULL) && pStreamConfig->IsEnabled;
273→        bool isWifiFirmwareUpdateMode = wifi_manager_IsWifiFirmwareUpdateActive();
274→
275→        // Check if streaming is to WiFi (which uses SPI bus and conflicts with SD)
276→        bool isWifiStreaming = isStreaming &&
277→                              (pStreamConfig->ActiveInterface == StreamingInterface_WiFi ||
278→                               pStreamConfig->ActiveInterface == StreamingInterface_All);
279→
280→        if (isWifiStreaming || isWifiFirmwareUpdateMode) {
281→            // WiFi streaming or firmware update mode active - suspend SD operations to avoid SPI bus contention
282→            // This prevents the ~590 second streaming failure and WiFi flash erase failures
283→            vTaskDelay(100 / portTICK_PERIOD_MS); // Reduced frequency check when SPI in use
284→        } else {
285→            // Safe to run SD operations (not streaming, or streaming to USB/SD only)
286→            // Normal SD card maintenance: driver tasks, state processing, file system
287→            DRV_SDSPI_Tasks(sysObj.drvSDSPI0);      // Harmony SD driver background processing
288→            sd_card_manager_ProcessState();         // SD card state management
289→            SYS_FS_Tasks();                         // File system maintenance
290→            vTaskDelay(SD_CARD_MANAGER_TASK_DELAY_MS / portTICK_PERIOD_MS); // 1ms normal rate
291→        }
292→    }
293→}
