438→// Client-specific SPI configuration management
439→bool SPI0_Context_Apply(spi0_client_t client)
440→{
441→    // Get client-specific frequency
442→    uint32_t frequency = (client == SPI0_CLIENT_WIFI) ? 
443→                        SPI0_WIFI_FREQUENCY_HZ : SPI0_SD_FREQUENCY_HZ;
444→    
445→    // Optimization: Skip setup if frequencies are identical (no switching needed)
446→    if (SPI0_WIFI_FREQUENCY_HZ == SPI0_SD_FREQUENCY_HZ) {
447→        return true;  // No frequency change needed
448→    }
449→    
450→    // Open temporary handle to SPI0 driver for frequency configuration
451→    DRV_HANDLE tempHandle = DRV_SPI_Open(DRV_SPI_INDEX_0, DRV_IO_INTENT_READWRITE);
452→    if (tempHandle == DRV_HANDLE_INVALID) {
453→        return false;
454→    }
455→    
456→    DRV_SPI_TRANSFER_SETUP setup = {
457→        .baudRateInHz = frequency,
458→        .chipSelect = SYS_PORT_PIN_NONE,  // Both clients manage their own CS
459→        .clockPhase = DRV_SPI_CLOCK_PHASE_VALID_LEADING_EDGE,
460→        .clockPolarity = DRV_SPI_CLOCK_POLARITY_IDLE_LOW,
461→        .dataBits = DRV_SPI_DATA_BITS_8
462→    };
463→    
464→    bool result = DRV_SPI_TransferSetup(tempHandle, &setup);
465→    
466→    // Close temporary handle
467→    DRV_SPI_Close(tempHandle);
468→    
469→    return result;
470→}
