472→bool SPI0_Operation_Lock(spi0_client_t client, TickType_t timeout)
473→{
474→    if (spi0_mutex == NULL || client >= SPI0_CLIENT_MAX) {
475→        return false;
476→    }
477→    
478→    TickType_t wait_time = (timeout == SPI0_MUTEX_USE_DEFAULT) ? 
479→                          pdMS_TO_TICKS(20) : timeout;
480→    
481→    if (xSemaphoreTake(spi0_mutex, wait_time) == pdTRUE) {
482→        // Apply client-specific SPI configuration (frequency optimization)
483→        SPI0_Context_Apply(client);
484→        
485→        current_owner = client;
486→        owner_task = xTaskGetCurrentTaskHandle();
487→        return true;
488→    }
489→    
490→    return false;
491→}
492→
493→void SPI0_Operation_Unlock(spi0_client_t client)
494→{
495→    if (spi0_mutex == NULL || client >= SPI0_CLIENT_MAX) {
496→        return;
497→    }
498→    
499→    if (current_owner == client && owner_task == xTaskGetCurrentTaskHandle()) {
500→        current_owner = SPI0_CLIENT_MAX;
501→        owner_task = NULL;
502→        xSemaphoreGive(spi0_mutex);
503→    }
504→}
