1206→/**
1207→ * SCPI Callback: Force DPDM detection
1208→ * Command: SYSTem:POWer:BQ:DPDM
1209→ * Triggers BQ24297 to re-run D+/D- detection.
1210→ *
1211→ * WARNING: Forcing DPDM while connected via USB will disrupt communication.
1212→ * DPDM re-detection temporarily resets IINLIM (potentially to 100mA),
1213→ * which can cause VBUS sag and USB disconnect on the host side.
1214→ * This command is intended for wall-charger debugging or pre-enumeration use.
1215→ */
1216→static scpi_result_t SCPI_ForceDPDM(scpi_t * context) {
1217→    // Read REG07
1218→    uint8_t reg7 = BQ24297_Read_I2C(0x07);
1219→    if (reg7 == 0xFF) {
1220→        scpi_printf(context, "I2C error: cannot read REG07\r\n");
1221→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1222→        return SCPI_RES_ERR;
1223→    }
1224→
1225→    // Set DPDM_EN bit (bit 7) to force detection
1226→    if (!BQ24297_Write_I2C(0x07, reg7 | 0x80)) {
1227→        scpi_printf(context, "I2C error: cannot write REG07\r\n");
1228→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1229→        return SCPI_RES_ERR;
1230→    }
1231→
1232→    // Wait for detection to complete (poll bit 7)
1233→    int timeout = 20;  // 2 seconds max
1234→    uint8_t status;
1235→    bool i2cOk = true;
1236→    do {
1237→        vTaskDelay(pdMS_TO_TICKS(100));
1238→        status = BQ24297_Read_I2C(0x07);
1239→        if (status == 0xFF) { i2cOk = false; break; }
1240→        timeout--;
1241→    } while ((status & 0x80) && timeout > 0);
1242→
1243→    if (!i2cOk) {
1244→        scpi_printf(context, "I2C error during DPDM polling\r\n");
1245→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1246→        return SCPI_RES_ERR;
1247→    }
1248→
1249→    if (timeout <= 0 && (status & 0x80)) {
1250→        scpi_printf(context, "DPDM timeout\r\n");
1251→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1252→        return SCPI_RES_ERR;
1253→    }
1254→
1255→    // Read result from REG08
1256→    uint8_t reg8 = BQ24297_Read_I2C(0x08);
1257→    const char* vbusStr[] = {"Unknown", "USB_SDP", "Adapter", "OTG"};
1258→
1259→    if (reg8 == 0xFF) {
1260→        scpi_printf(context, "DPDM complete but REG08 read failed\r\n");
1261→        SCPI_ErrorPush(context, SCPI_ERROR_SYSTEM_ERROR);
1262→        return SCPI_RES_ERR;
1263→    }
1264→
1265→    uint8_t vbusStat = (reg8 >> 6) & 0x03;
1266→    scpi_printf(context, "DPDM complete: VBUS=%s (%d), REG08=0x%02X\r\n",
1267→             vbusStr[vbusStat], vbusStat, reg8);
1268→    return SCPI_RES_OK;
1269→}
