1271→/**
1272→ * SCPI Callback: Comprehensive BQ24297 diagnostics report
1273→ * Command: SYSTem:POWer:BQ:DIAGnostics?
1274→ * Returns: Multi-section human-readable diagnostic dump
1275→ */

1276→static scpi_result_t SCPI_GetBQDiagnostics(scpi_t * context) {
1277→    tPowerData* pPower = (tPowerData*)BoardData_Get(
1278→            BOARDDATA_POWER_DATA,
1279→            0);
1280→    tBQ24297Data* pBQ = &pPower->BQ24297Data;
1281→
1282→    // Refresh cached status from hardware
