840→void UsbCdc_ProcessState() {
841→
842→    UNUSED(UsbCdc_WaitForRead); // We dont want to block on the read so this is currently not used
843→
844→    switch (gRunTimeUsbSttings.state) {
845→        case USB_CDC_STATE_INIT:
846→            //GPIO_WritePin(g_boardState.led2Id, false);
847→
848→            /* Open the device layer */
849→            gRunTimeUsbSttings.deviceHandle = USB_DEVICE_Open(USB_DEVICE_INDEX_0, DRV_IO_INTENT_READWRITE);
850→
851→            if (gRunTimeUsbSttings.deviceHandle != USB_DEVICE_HANDLE_INVALID) {
852→                /* Register a callback with device layer to get event notification (for end point 0) */
853→                USB_DEVICE_EventHandlerSet(
854→                        gRunTimeUsbSttings.deviceHandle,
855→                        UsbCdc_EventHandler,
856→                        0);
857→
858→                gRunTimeUsbSttings.state = USB_CDC_STATE_WAIT;
859→            } else {
860→                /* The Device Layer is not ready to be opened. We should try
861→                 * again later. */
862→            }
863→
864→            break;
865→        case USB_CDC_STATE_PROCESS:
866→            // If a write operation is not in progress
867→            if (gRunTimeUsbSttings.readTransferHandle ==
868→                    USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID) {
869→                // Process any input
870→                UsbCdc_FinalizeRead(&gRunTimeUsbSttings);
871→
872→                // Schedule the next read
873→                if (!UsbCdc_BeginRead(&gRunTimeUsbSttings)) {
874→                    break;
875→                }
876→            }
877→
878→            // I a read operation is not in progress
879→            if (gRunTimeUsbSttings.writeTransferHandle ==
880→                    USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID) {
881→                // Schedule any output;
882→                if (!UsbCdc_BeginWrite(&gRunTimeUsbSttings)) {
883→                    break;
884→                }
885→
886→            }
887→
888→            break;
889→        case USB_CDC_STATE_BEGIN_CLOSE:
890→            //GPIO_WritePin(g_boardState.led2Id, false);
891→
892→            if (gRunTimeUsbSttings.deviceHandle != USB_DEVICE_HANDLE_INVALID) {
893→                USB_DEVICE_Close(gRunTimeUsbSttings.deviceHandle);
894→                gRunTimeUsbSttings.deviceHandle = USB_DEVICE_HANDLE_INVALID;
895→
896→                gRunTimeUsbSttings.state = USB_CDC_STATE_WAIT;
897→            }
898→
899→            gRunTimeUsbSttings.state = USB_CDC_STATE_CLOSED;
900→
901→            break;
902→        case USB_CDC_STATE_CLOSED:
903→            //GPIO_WritePin(g_boardState.led2Id, false);
904→
905→            gRunTimeUsbSttings.deviceHandle = USB_DEVICE_HANDLE_INVALID;
906→
907→            gRunTimeUsbSttings.readTransferHandle =
908→                    USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID;
909→            gRunTimeUsbSttings.writeTransferHandle =
910→                    USB_DEVICE_CDC_TRANSFER_HANDLE_INVALID;
911→            gRunTimeUsbSttings.readBufferLength = 0;
912→
913→            gRunTimeUsbSttings.state = USB_CDC_STATE_INIT;
914→
915→            break;
916→        case USB_CDC_STATE_WAIT: // No action
917→        default:
918→            break;
919→    }
920→}
