536→    static const char UNSET_TRANSPARENT_MODE_COMMAND[] = "SYSTem:USB:SetTransparentMode 0"; // NOTE: PuTTY sends \r not \r\n by default so we are going to check for all terminating scenarios below
537→    static uint8_t transparentModeCmdLength = 0;
538→    
539→    if (client->readBufferLength > 0) {
540→        if (client->isTransparentModeActive == 0) {
541→            for (size_t i = 0; i < client->readBufferLength; ++i) {
542→                // Filter out potentially dangerous characters
543→                if (UsbCdc_IsCharacterSafe(client, client->readBuffer[i])) {
544→                    microrl_insert_char(&client->console, client->readBuffer[i]);
545→                } else {
546→                    // Silently reject unsafe characters to avoid information disclosure
547→                    // Character filtering is documented in the system design
548→                }
549→            }
550→            client->readBufferLength = 0;
551→            return true;
552→        } else { 
553→            // IMPORTANT: Transparent mode should NOT filter characters
554→            // This mode is used for raw binary data passthrough (e.g., firmware updates)
555→            // Filtering would corrupt the data stream
556→            
557→            // Check for UNSET_TRANSPARENT_MODE_COMMAND length plus up to two terminating characters (\n\r).
558→            transparentModeCmdLength = strlen(UNSET_TRANSPARENT_MODE_COMMAND);
559→            if ((client->readBufferLength == transparentModeCmdLength) ||       \
560→                (client->readBufferLength == transparentModeCmdLength + 1) ||   \
561→                (client->readBufferLength == transparentModeCmdLength + 2)) {
562→                //  Now check to see if the string actually matches the command UNSET_TRANSPARENT_MODE_COMMAND
563→                if ((strspn(UNSET_TRANSPARENT_MODE_COMMAND, (const char *)client->readBuffer)) == transparentModeCmdLength) {
564→                    for (size_t i = 0; i < transparentModeCmdLength; ++i) {
565→                        microrl_insert_char(&client->console, client->readBuffer[i]);
566→                    }
567→                    // Since we truncated the read buffer, be sure to pass the proper termination characters
568→                    microrl_insert_char(&client->console, '\n');
569→                    microrl_insert_char(&client->console, '\r');
570→                }
571→                client->readBufferLength = 0;
572→                return true;
573→            }
574→            if (UsbCdc_TransparentReadCmpltCB(client->readBuffer, client->readBufferLength) == true) {
575→                client->readBufferLength = 0;
