150→/*
151→ * Updates BQ24297 status by reading all registers
152→ * NOTE: Only called at boot - no I2C polling after init
153→ */
154→void BQ24297_UpdateStatus(void) {
155→
156→    uint8_t regData = 0;
157→    bool hasErrors = false;
158→
159→    // REG00: Input Source Control
160→    regData = BQ24297_Read_I2C(0x00);
161→    if (regData != 0xFF) {
162→        pData->status.hiZ = (bool) (regData & 0b10000000);
163→        pData->status.inLim = (uint8_t) (regData & 0b00000111);
164→    } else {
165→        hasErrors = true;
166→    }
167→
168→    // REG01: Power-On Configuration
169→    regData = BQ24297_Read_I2C(0x01);
170→    if (regData != 0xFF) {
171→        pData->status.otg = (bool) (regData & 0b00100000);
172→        pData->status.chgEn = (bool) (regData & 0b00010000);
173→    } else {
174→        hasErrors = true;
175→    }
176→
177→    // REG02: Charge Current Control
178→    regData = BQ24297_Read_I2C(0x02);
179→    if (regData != 0xFF) {
180→        pData->status.ichg = (uint8_t) (regData & 0b11111100) >> 2;
181→    } else {
182→        hasErrors = true;
183→    }
184→
185→    // REG07: Misc Operation Control
186→    regData = BQ24297_Read_I2C(0x07);
187→    if (regData != 0xFF) {
188→        pData->status.iinDet_Read = (bool) (regData & 0b10000000);
189→    } else {
190→        hasErrors = true;
191→    }
192→
193→    // REG08: System Status
194→    regData = BQ24297_Read_I2C(0x08);
195→    if (regData != 0xFF) {
196→        pData->status.vBusStat = (uint8_t) (regData & 0b11000000) >> 6;
197→        pData->status.chgStat = (uint8_t) (regData & 0b00110000) >> 4;
198→        pData->status.dpmStat = (bool) (regData & 0b00001000);
199→        pData->status.pgStat = (bool) (regData & 0b00000100);
200→        pData->status.thermStat = (bool) (regData & 0b00000010);
201→        pData->status.vsysStat = (bool) (regData & 0b00000001);
202→        
203→        // vsysStat = 1 means battery voltage < VSYSMIN (3.0V)
204→        // This is critical for power-up decisions
205→        // Only log status changes to reduce log spam
206→        static uint8_t lastReg08 = 0xFF;
207→        if (regData != lastReg08) {
208→            LOG_D("BQ24297: REG08=0x%02X vsysStat=%d (batt %s 3.0V) pgStat=%d vBusStat=%d", 
209→                  regData, pData->status.vsysStat, 
210→                  pData->status.vsysStat ? "<" : ">", 
211→                  pData->status.pgStat, pData->status.vBusStat);
212→                  
213→            // Extra logging when vsysStat indicates low battery
214→            if (pData->status.vsysStat) {
215→                LOG_D("BQ24297: Battery voltage < 3.0V (vsysStat=1)");
216→            }
217→            
218→            lastReg08 = regData;
219→        }
220→    } else {
221→        hasErrors = true;
222→    }
223→
224→    // REG09: Fault Status - Reading this resets fault flags!
225→    regData = BQ24297_Read_I2C(0x09);
226→    if (regData != 0xFF) {
227→        // First read resets faults, read again for current status
228→        regData = BQ24297_Read_I2C(0x09);
229→        if (regData != 0xFF) {
230→            pData->status.watchdog_fault = (bool) (regData & 0b10000000);
231→            pData->status.otg_fault = (bool) (regData & 0b01000000);
232→            pData->status.chgFault = (uint8_t) (regData & 0b00110000) >> 4;
233→            pData->status.bat_fault = (bool) (regData & 0b00001000);
234→            pData->status.ntcFault = (uint8_t) (regData & 0b00000011);
235→        }
236→    } else {
237→        hasErrors = true;
238→    }
239→    
240→    if (hasErrors) {
241→        LOG_E("BQ24297_UpdateStatus: I2C communication errors detected");
242→    }
243→    
244→    // Check for critical faults
245→    if (pData->status.bat_fault) {
246→        LOG_E("BQ24297: BATFET fault - battery disconnected from system!");
247→    }
248→}
