250→void BQ24297_ChargeEnable(bool chargeEnable) {
251→    // Temporary value to hold current register value
252→    uint8_t reg = 0;
253→
254→    reg = BQ24297_Read_I2C(0x01);
255→
256→    // OTG and Charge are mutually exclusive
257→    if (reg & 0x20) {
258→        return;  // OTG is enabled, cannot modify charge state
259→    }
260→
261→    if (pData->chargeAllowed && chargeEnable && pData->status.batPresent) {
262→        // Enable charging, preserve all bits except bit 4 (charge enable)
263→        reg = (reg & 0b11101111) | 0b00010000; // Clear bit 4, then set it
264→        BQ24297_Write_I2C(0x01, reg);
265→    } else {
266→        // Disable charging, preserve all bits except bit 4 (charge enable)
267→        reg = (reg & 0b11101111); // Just clear bit 4
268→        BQ24297_Write_I2C(0x01, reg);
269→    }
270→}
