356→bool BQ24297_Write_I2C(uint8_t reg, uint8_t txData) {
357→    uint8_t I2CData[2];
358→
359→    // Build data packet
360→    I2CData[0] = reg;
361→    I2CData[1] = txData;
362→
363→    if (pData->I2C_Handle != DRV_HANDLE_INVALID) {
364→        // Write to selected register with error checking
365→        bool success = DRV_I2C_WriteTransfer(
366→                        pData->I2C_Handle,
367→                        pConfigBQ24->I2C_Address,
368→                        I2CData,
369→                        2);
370→
371→        if (!success) {
372→            LOG_E("BQ24297_Write_I2C: Failed to write 0x%02X to register 0x%02X", txData, reg);
373→            return false;
374→        }
375→        return true;
376→    } else {
377→        LOG_E("BQ24297_Write_I2C: Invalid I2C handle");
378→        return false;
379→    }
380→}
381→
382→bool BQ24297_SetIINLIM(uint8_t iinlimCode) {
383→    // REG00 IINLIM is 3-bit field (bits 2:0), valid range 0-7 per datasheet Table 9-2
384→    if (iinlimCode > ILim_3000) return false;
385→    uint8_t reg = BQ24297_Read_I2C(0x00);
386→    if (reg == 0xFF) return false;
387→    // Clear HIZ (bit 7) and IINLIM (bits 2:0), preserve VINDPM (bits 6:3)
388→    reg = (reg & 0b01111000) | (iinlimCode & 0x07);
389→    bool success = BQ24297_Write_I2C(0x00, reg);
390→    if (!success) {
391→        LOG_E("BQ24297_SetIINLIM: Failed to write IINLIM code %u", iinlimCode);
392→    }
393→    return success;
394→}
395→
396→void BQ24297_ManageIINLIM(bool vbusPresent) {
397→    TickType_t now = xTaskGetTickCount();
398→
399→    switch (pData->iinlimState) {
400→        case IINLIM_STATE_IDLE:
401→            if (vbusPresent && !pData->iinlimLastVbus) {
402→                // Rising edge — VBUS just appeared
403→                LOG_D("IINLIM: VBUS appeared, entering WAIT_DPDM");
404→                pData->iinlimTimestamp = now;
405→                pData->iinlimState = IINLIM_STATE_WAIT_DPDM;
406→            }
407→            break;
408→
409→        case IINLIM_STATE_WAIT_DPDM:
410→            if (!vbusPresent) {
411→                LOG_D("IINLIM: VBUS lost during WAIT_DPDM, returning to IDLE");
412→                pData->iinlimState = IINLIM_STATE_IDLE;
413→                break;
414→            }
415→            {
416→                TickType_t elapsed = now - pData->iinlimTimestamp;
417→
418→                // Wait at least 1s after VBUS before acting on DPDM result
419→                // to ensure BQ24297 hardware has fully settled
420→                if (elapsed < pdMS_TO_TICKS(1000)) {
421→                    break;
422→                }
423→
424→                // Check REG07 bit 7 for DPDM in progress
425→                uint8_t reg07 = BQ24297_Read_I2C(0x07);
426→                bool dpdmDone = (reg07 != 0xFF) && !(reg07 & 0x80);
427→                bool timeout = elapsed >= pdMS_TO_TICKS(3000);
428→
429→                if (dpdmDone) {
430→                    // DPDM finished — safe to set IINLIM, hardware won't overwrite
431→                    if (BQ24297_SetIINLIM(ILim_500)) {
432→                        LOG_D("IINLIM: DPDM done after %lu ms, set 500mA, entering WAIT_USB",
433→                              (unsigned long)(elapsed * portTICK_PERIOD_MS));
434→                        pData->iinlimTimestamp = now;
435→                        pData->iinlimState = IINLIM_STATE_WAIT_USB;
436→                    } else {
437→                        LOG_E("IINLIM: Failed to set 500mA, retrying next cycle");
438→                    }
439→                } else if (timeout) {
440→                    // DPDM stuck after 3s — set IINLIM anyway
441→                    LOG_E("IINLIM: DPDM not complete after 3s (REG07=0x%02X), forcing 500mA",
442→                          reg07);
443→                    if (BQ24297_SetIINLIM(ILim_500)) {
444→                        pData->iinlimTimestamp = now;
445→                        pData->iinlimState = IINLIM_STATE_WAIT_USB;
446→                    } else {
447→                        LOG_E("IINLIM: Failed to set 500mA on timeout, retrying next cycle");
448→                    }
449→                }
450→            }
451→            break;
452→
453→        case IINLIM_STATE_WAIT_USB:
454→            if (!vbusPresent) {
455→                BQ24297_SetIINLIM(ILim_500);
456→                LOG_D("IINLIM: VBUS lost during WAIT_USB, reset to 500mA");
457→                pData->iinlimState = IINLIM_STATE_IDLE;
458→                break;
459→            }
460→            if ((now - pData->iinlimTimestamp) >= pdMS_TO_TICKS(2000)) {
461→                if (UsbCdc_IsConfigured()) {
462→                    // USB host enumerated — keep 500mA (USB-spec safe)
463→                    LOG_D("IINLIM: USB configured, keeping 500mA");
464→                    pData->iinlimState = IINLIM_STATE_SETTLED;
465→                } else {
466→                    // No USB enumeration — wall charger, bump to 2000mA
467→                    if (BQ24297_SetIINLIM(ILim_2000)) {
468→                        LOG_D("IINLIM: No USB config, set 2000mA (wall charger)");
469→                        pData->iinlimState = IINLIM_STATE_SETTLED;
470→                    } else {
471→                        LOG_E("IINLIM: Failed to set 2000mA, retrying next cycle");
472→                    }
473→                }
474→            }
475→            break;
476→
477→        case IINLIM_STATE_SETTLED:
478→            if (!vbusPresent) {
479→                BQ24297_SetIINLIM(ILim_500);
480→                LOG_D("IINLIM: VBUS lost, reset to 500mA");
481→                pData->iinlimState = IINLIM_STATE_IDLE;
482→            }
483→            break;
484→
485→        default:
486→            pData->iinlimState = IINLIM_STATE_IDLE;
487→            break;
488→    }
489→
490→    pData->iinlimLastVbus = vbusPresent;
491→}
492→
493→void BQ24297_EnableOTG(void) {
494→    // Read REG08 for safety checks
495→    uint8_t reg08 = BQ24297_Read_I2C(0x08);
496→    bool pgStat = (reg08 >> 2) & 0x01;
497→    uint8_t vbusStat = (reg08 >> 6) & 0x03;
498→    
499→    // Clear HIZ mode if active
500→    uint8_t reg00 = BQ24297_Read_I2C(0x00);
501→    if (reg00 & 0x80) {
502→        reg00 &= 0x7F;  // Clear bit 7 (HIZ)
503→        BQ24297_Write_I2C(0x00, reg00);
504→        vTaskDelay(5 / portTICK_PERIOD_MS);
505→    }
506→    
507→    // Cannot enable OTG if external power is present
508→    if (pgStat) {
509→        return;
510→    }
511→    
512→    // Check if OTG is already active
513→    if (vbusStat == 0x03) {
514→        uint8_t reg01 = BQ24297_Read_I2C(0x01);
515→        if (reg01 & 0x20) {
516→            pData->status.otg = true;
517→            pData->status.chgEn = false;
518→            return;
519→        }
520→    }
521→    
522→    // Set OTG GPIO HIGH to enable boost mode
523→    BATT_MAN_OTG_OutputEnable();
524→    BATT_MAN_OTG_Set();
525→    
526→    // Read current REG01 value
527→    uint8_t reg01 = BQ24297_Read_I2C(0x01);
528→    if (reg01 == 0xFF) {
529→        return;
530→    }
531→    
532→    // Configure REG01 for OTG mode
533→    // Bit 5 = 1 (OTG enable), Bit 4 = 0 (charge disable), Bit 6 = 1 (watchdog reset)
534→    reg01 = (reg01 & 0x0F) | 0x60;
535→    
536→    // Write with retry logic
537→    bool success = false;
538→    for (int retry = 0; retry < 3; retry++) {
539→        if (BQ24297_Write_I2C(0x01, reg01)) {
540→            vTaskDelay(5 / portTICK_PERIOD_MS);
541→            
542→            // Verify write
543→            uint8_t readback = BQ24297_Read_I2C(0x01);
544→            if ((readback & 0x30) == 0x20) {  // Check OTG=1, CHG=0
545→                success = true;
546→                break;
547→            }
548→        }
549→        vTaskDelay(10 / portTICK_PERIOD_MS);
550→    }
551→    
552→    if (!success) {
553→        BATT_MAN_OTG_Clear();  // Clear GPIO on failure
554→    }
555→    
556→    // Update status
557→    pData->status.otg = success;
558→    pData->status.chgEn = false;
559→}
560→
561→void BQ24297_DisableOTG(bool enableCharging) {
562→    // Clear HIZ mode if active
563→    uint8_t reg00 = BQ24297_Read_I2C(0x00);
564→    if (reg00 != 0xFF && (reg00 & 0x80)) {
565→        reg00 &= 0x7F;  // Clear bit 7
566→        BQ24297_Write_I2C(0x00, reg00);
567→        vTaskDelay(2 / portTICK_PERIOD_MS);
568→    }
569→    
570→    // Set GPIO LOW to disable OTG
571→    BATT_MAN_OTG_OutputEnable();
572→    BATT_MAN_OTG_Clear();
573→    vTaskDelay(2 / portTICK_PERIOD_MS);
574→    
575→    // Read and modify REG01
576→    uint8_t reg = BQ24297_Read_I2C(0x01);
577→    if (reg == 0xFF) {
578→        pData->status.otg = false;
579→        return;
580→    }
581→    
582→    // Clear OTG bit (bit 5), set watchdog reset (bit 6)
583→    // Keep SYS_MIN at 3.0V (bits 3:1 = 000)
584→    reg = (reg & 0b11010001) | 0b01000001;
585→    
586→    // Set charge enable if requested
587→    if (enableCharging) {
588→        reg |= 0b00010000;
589→    }
590→    
591→    // Write the new value
592→    if (!BQ24297_Write_I2C(0x01, reg)) {
593→        return;
594→    }
595→    
596→    // Check for HIZ mode after REG01 write
597→    vTaskDelay(5 / portTICK_PERIOD_MS);
598→    reg00 = BQ24297_Read_I2C(0x00);
599→    if (reg00 != 0xFF && (reg00 & 0x80)) {
600→        reg00 &= 0x7F;
601→        BQ24297_Write_I2C(0x00, reg00);
602→    }
603→    
604→    // Update local status
605→    pData->status.otg = false;
606→    pData->status.chgEn = (reg & 0x10) ? true : false;
607→    
608→    // Give the BQ24297 time to perform input detection
609→    vTaskDelay(50 / portTICK_PERIOD_MS);
610→    
611→    // Update status to reflect changes
612→    BQ24297_UpdateStatus();
613→}
614→
615→bool BQ24297_IsOTGEnabled(void) {
616→    uint8_t reg = BQ24297_Read_I2C(0x01);
617→    return (reg & 0b00100000) != 0;
618→}
619→
620→bool BQ24297_IsChargingEnabled(void) {
621→    uint8_t reg = BQ24297_Read_I2C(0x01);
622→    return (reg & 0b00010000) != 0;
623→}
624→
625→bool BQ24297_IsBatteryPresent(void) {
626→    // Battery detection logic:
627→    // 1. If thermistor reads COLD (open circuit), battery is disconnected
628→    // 2. If thermistor reads HOT, it's stuck low (shorted) - battery may be present but charging unsafe
629→    // 3. Normal thermistor AND voltage > 3.0V indicates battery present
630→    
631→    // Update status to get latest NTC and voltage readings
632→    BQ24297_UpdateStatus();
633→    
634→    // NTC_FAULT_COLD (2) = thermistor open = no battery
635→    if (pData->status.ntcFault == NTC_FAULT_COLD) {
636→        return false;
637→    }
638→    
639→    // NTC_FAULT_HOT (1) = thermistor shorted/stuck low - unsafe to charge
640→    if (pData->status.ntcFault == NTC_FAULT_HOT) {
641→        // Battery might be present but thermistor is faulty
642→        // Check voltage to confirm battery presence
643→        return !pData->status.vsysStat;  // Battery present if voltage > 3.0V
644→    }
645→    
646→    // Normal thermistor reading - battery is present
647→    return true;
648→}
649→
650→void BQ24297_UpdateBatteryStatus(void) {
651→    bool oldBatPresent = pData->status.batPresent;
652→    bool oldChargeAllowed = pData->chargeAllowed;
653→
654→    pData->status.batPresent = BQ24297_IsBatteryPresent();
655→    pData->chargeAllowed = pData->status.batPresent &&
656→                           (pData->status.ntcFault != NTC_FAULT_HOT);
657→
658→    // Enforce charge state via I2C when chargeAllowed changes
659→    if (pData->chargeAllowed != oldChargeAllowed) {
660→        BQ24297_ChargeEnable(pData->chargeAllowed);
661→        LOG_D("BQ24297: Charging %s",
662→              pData->chargeAllowed ? "enabled" : "disabled");
663→    }
664→
665→    if (oldBatPresent != pData->status.batPresent) {
666→        LOG_D("BQ24297: Battery %s",
667→              pData->status.batPresent ? "detected" : "not detected");
668→    }
669→}
670→
671→void BQ24297_SetPowerMode(bool externalPowerPresent) {
672→    static bool lastExternalPowerState = false;
673→    static bool initialized = false;
674→
675→    // Only log when state actually changes
676→    if (!initialized || lastExternalPowerState != externalPowerPresent) {
677→        if (externalPowerPresent) {
678→            LOG_D("BQ24297_SetPowerMode: External power detected");
679→        } else {
680→            LOG_D("BQ24297_SetPowerMode: Battery power only");
681→        }
682→        lastExternalPowerState = externalPowerPresent;
683→        initialized = true;
684→    }
685→
686→    // OTG mode is disabled by default in the BQ24297 and set to disabled at init.
687→    // Charging is always enabled and handled autonomously by the hardware.
688→    // No action needed here - just logging state changes above.
689→}
